import { Ionicons } from '@expo/vector-icons';
import { router } from 'expo-router';
import React, { useState, useEffect } from 'react';
import { View, Text, Alert, Pressable } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';

import { AnimatedSection } from '@/components/animations/AnimatedSection';
import { GlassCard } from '@/components/ui/GlassCard';
import { PremiumBackground } from '@/components/ui/PremiumBackground';
import { apiService } from '@/services/api.service';
import { useAuthStore } from '@/store/auth.store';
import { THEME } from '@/theme/theme';

export default function RecoveryScreen() {
  const { profile, refreshProfile, clearSession, role } = useAuthStore();

  const [loading, setLoading] = useState(false);
  const [daysRemaining, setDaysRemaining] = useState<number | null>(null);

  useEffect(() => {
    if (profile?.permanent_deletion_at) {
      const permanentDate = new Date(profile.permanent_deletion_at);

      const now = new Date();

      const diffMs = permanentDate.getTime() - now.getTime();

      const diffDays = Math.ceil(diffMs / (1000 * 60 * 60 * 24));

      setDaysRemaining(diffDays > 0 ? diffDays : 0);
    } else {
      setDaysRemaining(30);
    }
  }, [profile]);

  const handleRestore = async () => {
    setLoading(true);

    try {
      await apiService.restoreAccount();

      await refreshProfile();

      Alert.alert('Account Restored', 'Welcome back!');

      const target = role === 'Owner' ? '/(owner)' : '/(customer)';
      router.replace(target as '/(owner)' | '/(customer)');
    } catch (err: unknown) {
      const error = err as Error;
      Alert.alert('Restore Failed', error?.message || 'Could not restore account.');
    } finally {
      setLoading(false);
    }
  };

  const handleHardDelete = () => {
    Alert.alert(
      'Permanent Deletion',
      'Are you absolutely sure? This action cannot be undone and all your data will be permanently deleted.',
      [
        {
          text: 'Cancel',
          style: 'cancel',
        },
        {
          text: 'Delete Permanently',
          style: 'destructive',
          onPress: async () => {
            setLoading(true);

            try {
              await apiService.hardDeleteAccount();

              await clearSession();

              router.replace('/(public)/welcome');
            } catch (err: unknown) {
              const error = err as Error;
              Alert.alert('Deletion Failed', error?.message || 'Could not delete account.');

              setLoading(false);
            }
          },
        },
      ],
    );
  };

  return (
    <PremiumBackground>
      <SafeAreaView className="flex-1 justify-center px-6">
        <AnimatedSection direction="up">
          <GlassCard className="p-2 rounded-full border border-border items-center">
            {/* Icon */}
            <View className="rounded-full items-center justify-center mb-8 mt-6">
              <Ionicons name="trash-outline" size={42} color={THEME.colors.error} />
            </View>

            {/* Title */}
            <Text className="text-white text-4xl font-black text-center leading-tight mb-4">
              Account{'\n'}Deactivated
            </Text>

            {/* Description */}
            <Text className="text-textSecondary text-center text-lg leading-8 mb-8 px-2">
              Your account is currently scheduled for permanent deletion.
            </Text>

            {/* Days Remaining */}
            {daysRemaining !== null && (
              <Text className="text-error text-center text-2xl font-black leading-10 mb-10">
                It will be permanently deleted in {daysRemaining} days.
              </Text>
            )}

            {/* Buttons */}
            <View className="gap-y-3">
              {/* Restore */}
              <Pressable
                onPress={handleRestore}
                disabled={loading}
                className="bg-primary rounded-full py-5 items-center justify-center active:opacity-80"
              >
                <Text className="text-black font-black text-sm uppercase tracking-0.5">
                  {loading ? 'Processing...' : 'Restore Account'}
                </Text>
              </Pressable>

              {/* Delete */}
              <Pressable
                onPress={handleHardDelete}
                disabled={loading}
                className="border border-red-500 rounded-full py-5 items-center justify-center active:opacity-80"
              >
                <Text className="px-3 text-red-500 font-black text-sm uppercase tracking-1">
                  Delete Permanently
                </Text>
              </Pressable>
            </View>
          </GlassCard>
        </AnimatedSection>
      </SafeAreaView>
    </PremiumBackground>
  );
}

import React from 'react';
import { View } from 'react-native';
import { SafeAreaView, useSafeAreaInsets } from 'react-native-safe-area-context';

import type { ViewProps } from 'react-native';

interface ScreenProps extends ViewProps {
  safeArea?: boolean;
  edges?: ('top' | 'right' | 'bottom' | 'left')[];
  className?: string;
}

export const Screen: React.FC<ScreenProps> = ({
  children,
  safeArea = true,
  edges = ['top', 'bottom', 'left', 'right'],
  className = '',
  style,
  ...props
}) => {
  const insets = useSafeAreaInsets();

  if (safeArea) {
    return (
      <SafeAreaView
        edges={edges}
        className={`flex-1 bg-background ${className}`}
        style={style}
        {...props}
      >
        {children}
      </SafeAreaView>
    );
  }

  return (
    <View className={`flex-1 bg-background ${className}`} style={style} {...props}>
      {children}
    </View>
  );
};

import { Image } from 'expo-image';
import React, { useState } from 'react';
import { View, Text, StyleSheet, Platform } from 'react-native';

import type { StyleProp, ViewStyle } from 'react-native';
import BusinessIcon from '../../../assets/Business.svg';
import CustomerIcon from '../../../assets/Customer.svg';
import { useProfileMedia } from '@/hooks/useProfileMedia';
import { THEME } from '@/theme/theme';

interface AvatarProps {
  url?: string | null;
  userId?: string | null;
  name?: string;
  size?: number;
  style?: StyleProp<ViewStyle>;
  className?: string;
  type?: 'customer' | 'business' | 'default';
}

const AvatarBase: React.FC<AvatarProps> = ({
  url,
  userId,
  name = '',
  size = 48,
  style,
  className,
  type = 'default',
}) => {
  const [hasError, setHasError] = useState(false);

  const radius = size / 2;

  const getInitials = (str: string) => {
    const parts = str.trim().split(/\s+/);

    if (!parts.length || !parts[0]) return 'U';

    if (parts.length === 1) {
      return parts[0].substring(0, 2).toUpperCase();
    }

    return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
  };

  const getHashColor = (str: string) => {
    let hash = 0;

    for (let i = 0; i < str.length; i++) {
      hash = str.charCodeAt(i) + ((hash << 5) - hash);
    }

    const colors = [
      THEME.colors.background,
      THEME.colors.border,
      THEME.colors.card,
      THEME.colors.border,
      THEME.colors.textSecondary,
      THEME.colors.textSecondary,
    ];

    return colors[Math.abs(hash) % colors.length];
  };

  const { data: mediaUrl } = useProfileMedia(userId);

  const resolvedUrl = mediaUrl || url;

  const showFallback =
    !resolvedUrl || resolvedUrl === 'undefined' || resolvedUrl === 'null' || hasError;

  return (
    <View
      className={className}
      style={[
        styles.container,
        {
          width: size,
          height: size,
        },
        style,
      ]}
    >
      {showFallback ? (
        type === 'customer' ? (
          <CustomerIcon width={size * 0.6} height={size * 0.6} color={THEME.colors.primary} />
        ) : type === 'business' ? (
          <BusinessIcon width={size * 0.6} height={size * 0.6} color={THEME.colors.primary} />
        ) : (
          <Text
            style={[
              styles.initials,
              {
                fontSize: size * 0.4,
              },
            ]}
          >
            {getInitials(name)}
          </Text>
        )
      ) : (
        <Image
          source={{ uri: resolvedUrl }}
          style={[
            {
              width: size,
              height: size,
              borderRadius: radius,
            },
          ]}
          contentFit="cover"
          transition={Platform.OS === 'android' ? 0 : 200}
          onError={() => setHasError(true)}
        />
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    justifyContent: 'center',
    alignItems: 'center',
    overflow: 'hidden',
  },

  initials: {
    color: THEME.colors.text,
    fontWeight: '700',
  },
});

export const Avatar = React.memo(AvatarBase);

