                  size={18}
                  color={THEME.colors.textSecondary}
                />

                <Text className="text-textSecondary text-xs leading-6 flex-1">
                  Please arrive 5–10 minutes before your scheduled appointment. You can manage this
                  booking anytime from the My Bookings section.
                </Text>
              </View>
            </GlassCard>
          </AnimatedSection>

          {/* Buttons */}
          <AnimatedSection direction="up" delay={250} className="gap-y-3 mt-auto">
            <PremiumButton
              title="View My Bookings"
              onPress={() => router.replace('/(customer)/bookings')}
              className="w-full h-14 bg-primary rounded-2xl"
            />

            <Pressable
              onPress={() => router.replace('/(customer)')}
              className="w-full h-14 rounded-2xl  bg-card items-center justify-center"
            >
              <Text className="text-text font-bold text-base">Back to Dashboard</Text>
            </Pressable>
          </AnimatedSection>
        </ScrollView>
      </SafeAreaView>
    </PremiumBackground>
  );
}

import { Ionicons } from '@expo/vector-icons';
import dayjs from 'dayjs';
import { router } from 'expo-router';
import React, { useState, useMemo } from 'react';
import { View, Text, Pressable, FlatList, RefreshControl } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';

import { AnimatedSection } from '@/components/animations/AnimatedSection';
import { Avatar } from '@/components/ui/Avatar';
import { Badge } from '@/components/ui/Badge';
import { GlassCard } from '@/components/ui/GlassCard';
import { LoadingSkeleton } from '@/components/ui/LoadingSkeleton';
import { PremiumBackground } from '@/components/ui/PremiumBackground';
import { useBookings } from '@/hooks/useBookings';
import { getBookingPrice } from '@/services/api.service';
import { THEME } from '@/theme/theme';
import { formatBookingDate, formatBookingTime } from '@/utils/time';

import type { Booking } from '@/features/booking/types/booking.types';
import type { Service } from '@/features/shared/types/business.types';

type BookingFilterType = 'upcoming' | 'completed' | 'cancelled';

export default function CustomerBookingsScreen() {
  const [filter, setFilter] = useState<BookingFilterType>('upcoming');
  const [refreshing, setRefreshing] = useState(false);
  const { data: bookings, isLoading, isError, refetch } = useBookings('Customer');

  const filteredBookings = useMemo(() => {
    if (!bookings) return [];
    const now = dayjs();

    return bookings.filter((b: Booking) => {
      let status = (b.status || 'pending').toLowerCase();
      const bookingDateTime = dayjs(`${b.date} ${b.time}`);
      const bookingEndTime = bookingDateTime.add(b.duration || 60, 'minutes'); // Default to 60 mins if duration not present

      // Auto-categorize based on time
      if (now.isAfter(bookingEndTime)) {
        if (status === 'confirmed') {
          status = 'completed'; // Confirmed and time passed -> Completed
        } else if (status === 'pending') {
          status = 'cancelled'; // Pending and time passed -> Cancelled (auto-rejected)
        }
      }

      // Check for expired confirmed bookings
      if (status === 'confirmed') {
        if (bookingEndTime.isBefore(now)) {
          status = 'completed'; // Treat as completed if end time has passed
        }
      }

      if (filter === 'upcoming') {
        return status === 'pending' || status === 'confirmed';
      }
      if (filter === 'completed') {
        return status === 'completed';
      }
      if (filter === 'cancelled') {
        return (
          status === 'cancelled' ||
          status === 'rejected' ||
          status === 'expired' ||
          status === 'no_show'
        );
      }
      return true;
    });
  }, [bookings, filter]);

  const onRefresh = async () => {
    setRefreshing(true);
    await refetch();
    setRefreshing(false);
  };

  const renderBookingCard = ({ item, index }: { item: Booking; index: number }) => {
    const salonName = item.business?.salon_name || item.salon?.salon_name || 'Business Partner';

    const salonAddress = item.business?.address || item.salon?.address || 'Premium Suite';

    const salonImage =
      item.business?.owner_image ||
      item.business?.image_url ||
      item.salon?.owner_image ||
      item.salon?.image_url ||
      null;

    const displayPrice = getBookingPrice(item);

    return (
      <AnimatedSection delay={index * 30} direction="up" className="mb-3">
        <GlassCard className="bg-card rounded-3xl p-1 shadow-sm overflow-hidden">
          {/* Tappable top section → booking detail */}
          <Pressable onPress={() => router.push(`/booking-detail/${item.id}`)}>
            {/* Top */}
            <View className="flex-row items-center">
              {/* Avatar */}
              <View className="relative">
                <Avatar
                  userId={item.business?.owner_user_id || item.salon?.owner_user_id}
                  name={salonName}
                  size={70}
                  type="business"
                  className="w-20 h-20 rounded-full"
                />
              </View>

              {/* Right Content */}
              <View className="flex-1 ml-3 justify-center">
                {/* Name + Badge */}
                <View className="flex-row items-center justify-between">
                  <Text className="flex-1 text-text text-xl font-black mr-3" numberOfLines={1}>
                    {salonName}
                  </Text>

                  <Badge status={item.status as Booking['status']} />
                </View>
                {/* Location */}
                <View className="flex-row items-center mt-1">
                  <Ionicons name="location-outline" size={13} color={THEME.colors.textSecondary} />

                  <Text className="text-textSecondary text-sm ml-1 flex-1" numberOfLines={1}>
                    {salonAddress}
                  </Text>
                </View>
              </View>
            </View>
            <View className="h-[1px] bg-border my-2" />

            {/* Service + Price */}
            <View className="flex-row items-start justify-between">
              {/* Service */}
              <View className="flex-1">
                <Text className="text-xs uppercase tracking-0.5 text-textSecondary font-black">
                  Service
                </Text>

                <Text className="text-text text-xl font-bold mt-1" numberOfLines={1}>
                  {item.services && item.services.length > 0
                    ? item.services.map((s: Service) => s.name).join(', ')
                    : item.service?.name || 'Curated Session'}
                </Text>
              </View>

              {/* Price */}
              <View className="items-end">
                <Text className="text-text text-4xl font-black tracking-tight">
                  ₹{displayPrice % 1 === 0 ? displayPrice.toFixed(0) : displayPrice.toFixed(2)}
                </Text>
              </View>
            </View>
          </Pressable>

          {/* Bottom — date/time + rebook, isolated from the card press */}
          <View className="flex-row items-center justify-between pt-2 border-t border-border">
            {/* Date & Time */}
            <Pressable
              className="flex-row items-center flex-1 mr-3"
              onPress={() => router.push(`/booking-detail/${item.id}`)}
            >
              <Ionicons name="calendar-outline" size={15} color={THEME.colors.textSecondary} />

              <Text className="text-textSecondary text-sm font-semibold ml-1">
                {formatBookingDate(item.date)} • {formatBookingTime(item.time)}
              </Text>
            </Pressable>

            {/* Rebook */}
            {(item.status === 'confirmed' ||
              item.status === 'completed' ||
              item.status === 'cancelled' ||
              item.status === 'rejected' ||
              item.status === 'no_show') && (
              <Pressable
                onPress={() => {
                  const serviceIds =
                    item.services?.map((s: Service) => s.id).join(',') || item.service?.id || '';

                  router.push({
                    pathname: '/(customer)/book/[id]',
                    params: {
                      id: item.business_id || item.business?.id || item.salon?.id || '',
                      serviceIds,
                    },
                  });
                }}
                className="px-4 py-2 rounded-full border border-text"
              >
                <Text className="text-text text-xs font-black uppercase tracking-wide">Rebook</Text>
              </Pressable>
            )}
          </View>
        </GlassCard>
      </AnimatedSection>
    );
  };

  return (
    <PremiumBackground>
      <SafeAreaView className="flex-1" edges={['top']}>
        {/* Cinematic Page Title */}
        <View className="px-luxury pt-5 pb-2">
          <Text className="text-textSecondary text-xs font-black uppercase tracking-1 mb-1">
            My Bookings
          </Text>
          <Text className="text-text text-3xl font-black tracking-tight">
            Your <Text className="text-primary">Appointments</Text>
          </Text>
        </View>

        {/* Custom Header Tab Bar */}
        <View className="flex-row px-luxury pt-3 pb-1 border-b border-border bg-card mt-2">
          {(['upcoming', 'completed', 'cancelled'] as const).map((tab) => (
            <Pressable
              key={tab}
              className={`flex-1 py-3 items-center border-b-2 ${
                filter === tab ? 'border-primary' : 'border-transparent'
              }`}
              onPress={() => setFilter(tab)}
            >
              <Text
                className={`text-xs font-black uppercase tracking-wider ${
                  filter === tab ? 'text-primary' : 'text-textSecondary'
                }`}
              >
                {tab}
              </Text>
            </Pressable>
          ))}
        </View>

        {isLoading ? (
          <View className="flex-1 px-luxury pt-6">
            <LoadingSkeleton height={140} borderRadius={20} className="mb-4" />
            <LoadingSkeleton height={140} borderRadius={20} className="mb-4" />
            <LoadingSkeleton height={140} borderRadius={20} />
          </View>
        ) : isError ? (
          <View className="flex-1 justify-center items-center px-luxury">
            <GlassCard className="items-center w-full bg-card p-6">
              <Ionicons name="alert-circle-outline" size={48} color={THEME.colors.error} />
              <Text className="text-text text-lg font-bold mt-4 text-center">
                Failed to load your reservations
              </Text>
              <Pressable
                onPress={() => refetch()}
                className="mt-6 bg-error/10 border border-error/30 px-8 py-3 rounded-full"
              >
                <Text className="text-error font-bold">Retry Connection</Text>
              </Pressable>
            </GlassCard>
          </View>
        ) : (
          <FlatList
            data={filteredBookings}
            renderItem={renderBookingCard}
            keyExtractor={(item, index) => item.id || `booking-${index}`}
            contentContainerClassName="px-luxury pt-6 pb-24"
            showsVerticalScrollIndicator={false}
            refreshControl={
              <RefreshControl
                refreshing={refreshing}
                onRefresh={onRefresh}
                tintColor={THEME.colors.primary}
                colors={[THEME.colors.primary]}
              />
            }
            ListEmptyComponent={
              <AnimatedSection direction="up" className="items-center justify-center pt-24">
                <View className="w-20 h-20 rounded-full items-center justify-center mb-6  ">
                  <Ionicons
                    name="calendar-clear-outline"
                    size={36}
                    color={THEME.colors.textSecondary}
                  />
                </View>
                <Text className="text-text text-xl font-black uppercase tracking-tight mb-2">
                  No Bookings Found
                </Text>
                <Text className="text-textSecondary text-center px-8 text-sm leading-relaxed">
                  You have no {filter} booking schedules recorded under this account at the moment.
                </Text>
              </AnimatedSection>
            }
          />
        )}
      </SafeAreaView>
    </PremiumBackground>
  );
}

import { Ionicons } from '@expo/vector-icons';
import dayjs from 'dayjs';
import { router, useFocusEffect } from 'expo-router';
import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { View, Text, ScrollView, Pressable } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';

import { AnimatedSection } from '@/components/animations/AnimatedSection';
import { LoadingSkeleton } from '@/components/ui/LoadingSkeleton';
import { PremiumBackground } from '@/components/ui/PremiumBackground';
import { BusinessCard } from '@/features/customer/components/BusinessCard';
import { DealCard } from '@/features/customer/components/DealCard';
import { HomeSearchBar } from '@/features/customer/components/HomeSearchBar';
import { NearbySalonCard } from '@/features/customer/components/NearbySalonCard';
import { TrendingServiceCard } from '@/features/customer/components/TrendingServiceCard';
import { useBookings } from '@/hooks/useBookings';
import { useBusinesses, useCategories } from '@/hooks/useBusinesses';
import { useDashboard } from '@/hooks/useDashboard';
import { useLocation } from '@/hooks/useLocation';
import { useAuthStore } from '@/store/auth.store';
import { THEME } from '@/theme/theme';

import type { FlashDeal } from '@/features/customer/components/DealCard';
import type { TrendingService } from '@/features/customer/components/TrendingServiceCard';
import type { Booking } from '@/types/booking.types';
import type { Business } from '@/types/business.types';

// New Components

const calculateDistanceKm = (lat1: number, lon1: number, lat2: number, lon2: number) => {
  if (!lat1 || !lon1 || !lat2 || !lon2) return Infinity;
  const R = 6371; // km
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLon = ((lon2 - lon1) * Math.PI) / 180;
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos((lat1 * Math.PI) / 180) *
      Math.cos((lat2 * Math.PI) / 180) *
      Math.sin(dLon / 2) *
      Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
};

export default function CustomerHomeScreen() {
  const { user, profile } = useAuthStore();
  const { data: businesses, refetch } = useBusinesses();

  const { data: categories } = useCategories();
  const {
    data: bookings,

    isLoading: bookingsLoading,
    refetch: refetchBookings,
  } = useBookings('Customer');

  const [searchQuery, setSearchQuery] = useState('');

  const {
    userLocation,
    locationLoading,
    useCurrentLocation,
    setUseCurrentLocation,
    getUserLocation,
  } = useLocation();

  // New Dashboard Hook using real coordinates if available
  const {
    nearbySalons,
    isLoadingNearby,
    refetchNearby,
    trendingServices,
    isLoadingTrending,
    flashDeals,
    isLoadingDeals,
  } = useDashboard(
    useCurrentLocation ? userLocation?.latitude : null,
    useCurrentLocation ? userLocation?.longitude : null,
  );

  const filteredNearbySalons = useMemo(() => {
    let list = nearbySalons;

    if (useCurrentLocation && userLocation) {
      list = list.filter((salon) => {
        if (salon.distance_km !== undefined) return salon.distance_km <= 10;
        const b = businesses?.find((b) => b.id === salon.id);
        if (!b?.latitude || !b?.longitude) return false;
        return (
          calculateDistanceKm(
            userLocation.latitude,
            userLocation.longitude,
            b.latitude,
            b.longitude,
          ) <= 10
        );
      });
    }

    // Fallback if nearby filtering leaves us with nothing
    if (list.length === 0 && businesses && businesses.length > 0) {
      list = businesses.slice(0, 5); // Use general businesses as fallback, max 5 items
    }

    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      list = list.filter(
        (salon) =>
          salon.salon_name?.toLowerCase().includes(query) ||
          salon.address?.toLowerCase().includes(query),
      );
    }
    return list;
  }, [nearbySalons, searchQuery, useCurrentLocation, userLocation, businesses]);

  const enrichedTrendingServices = useMemo(() => {
    if (!trendingServices) return [];
    return trendingServices.map((service: TrendingService) => {
      const business = businesses?.find((b) => b.id === service.business_id);
      return {
        ...service,
        business: business || service.business || null,
        salon_name: business?.salon_name || service.salon_name,
        rating_avg: business?.rating_avg || service.rating_avg,
      };
    });
  }, [trendingServices, businesses]);

  const filteredTrendingServices = useMemo(() => {
    let list = enrichedTrendingServices;

    if (useCurrentLocation && userLocation) {
      list = list.filter((service) => {
        const b = service.business;
        if (!b?.latitude || !b?.longitude) return false;
        return (
          calculateDistanceKm(
            userLocation.latitude,
            userLocation.longitude,
            b.latitude,
            b.longitude,
          ) <= 10
        );
      });
    }

    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      list = list.filter(
        (service) =>
          service.name?.toLowerCase().includes(query) ||
          service.salon_name?.toLowerCase().includes(query),
      );
    }
    return list.sort((a, b) => {
      const ratingA = a.rating_avg ? Number(a.rating_avg) : 0;
      const ratingB = b.rating_avg ? Number(b.rating_avg) : 0;
      return ratingB - ratingA;
    });
  }, [enrichedTrendingServices, searchQuery, useCurrentLocation, userLocation]);

  const enrichedFlashDeals = useMemo(() => {
    if (!flashDeals) return [];
    return flashDeals.map((deal: FlashDeal) => {
      const business = businesses?.find((b) => b.id === deal.business_id);
      return {
        ...deal,
        business: business || deal.business || null,
        salon_name: business?.salon_name || deal.salon_name,
      };
    });
  }, [flashDeals, businesses]);

  const filteredFlashDeals = useMemo(() => {
    let list = enrichedFlashDeals;

    if (useCurrentLocation && userLocation) {
      list = list.filter((deal) => {
        const b = deal.business;
        if (!b?.latitude || !b?.longitude) return false;
        return (
          calculateDistanceKm(
            userLocation.latitude,
            userLocation.longitude,
            b.latitude,
            b.longitude,
          ) <= 10
        );
      });
    }

    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      list = list.filter(
        (deal) =>
          deal.title?.toLowerCase().includes(query) ||
          deal.salon_name?.toLowerCase().includes(query),
      );
    }
    return list;
  }, [enrichedFlashDeals, searchQuery, useCurrentLocation, userLocation]);

  useFocusEffect(
    useCallback(() => {
      refetchBookings();
      refetch();
      refetchNearby();
    }, [refetchBookings, refetch, refetchNearby]),
  );

  useEffect(() => {
    // Auto-fetch location only once when home screen mounts
    if (!useCurrentLocation && !userLocation) {
      const fetchInitialLocation = async () => {
        const success = await getUserLocation(true); // silent fetch
        if (success) {
          setUseCurrentLocation(true);
        }
      };
      fetchInitialLocation();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const normalizedBookings = useMemo(() => {
    if (!bookings) return [];
    const now = dayjs();
    return bookings.map((b: Booking) => {
      let status = (b.status || 'pending').toLowerCase();
      const bookingDateTime = dayjs(`${b.date} ${b.time}`);
      const bookingEndTime = bookingDateTime.add(b.duration || 60, 'minutes');

      if (now.isAfter(bookingEndTime)) {
        if (status === 'confirmed') status = 'completed';
        else if (status === 'pending') status = 'cancelled';
      }
      if (status === 'confirmed' && bookingEndTime.isBefore(now)) {
        status = 'completed';
      }

      return { ...b, normalizedStatus: status };
    });
  }, [bookings]);

  const upcomingBooking = useMemo(() => {
    return normalizedBookings.find(
      (b: Booking & { normalizedStatus?: string }) =>
        b.normalizedStatus === 'pending' || b.normalizedStatus === 'confirmed',
    );
  }, [normalizedBookings]);

  const favouriteSalons = useMemo(() => {
    if (!normalizedBookings || !businesses) return [];
    const completedBookings = normalizedBookings.filter(
      (b: Booking & { normalizedStatus?: string }) => b.normalizedStatus === 'completed',
    );
    const sortedBookings = [...completedBookings].sort((a: Booking, b: Booking) => {
      const dateA = dayjs(`${a.date} ${a.time}`);
      const dateB = dayjs(`${b.date} ${b.time}`);
      return dateB.isAfter(dateA) ? 1 : -1;
    });

    const visitedBusinessIds = Array.from(
      new Set(sortedBookings.map((b: Booking) => b.business_id || b.business?.id).filter(Boolean)),
    );
    return visitedBusinessIds
      .map((id) => businesses.find((b) => b.id === id))
      .filter((b): b is Business => Boolean(b) && b!.suspended !== true && b!.deleted_at == null);
  }, [normalizedBookings, businesses]);

  const filteredFavouriteSalons = useMemo(() => {
    let list = favouriteSalons;

    if (useCurrentLocation && userLocation) {
      list = list.filter((salon) => {
        if (!salon?.latitude || !salon?.longitude) return false;
        return (
          calculateDistanceKm(
            userLocation.latitude,
            userLocation.longitude,
            salon.latitude,
            salon.longitude,
          ) <= 10
        );
      });
    }

    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      list = list.filter(
        (salon) =>
          salon.salon_name?.toLowerCase().includes(query) ||
          salon.address?.toLowerCase().includes(query),
      );
    }
    return list;
  }, [favouriteSalons, searchQuery, useCurrentLocation, userLocation]);

  const handleBusinessPress = (id: string) => {
    router.push(`/(customer)/browse/salons/${id}`);
  };

  return (
    <PremiumBackground>
      <SafeAreaView className="flex-1" edges={['top']}>
        <ScrollView showsVerticalScrollIndicator={false} contentContainerClassName="pb-12">
          {/* 1. GREETING + SEARCH */}
          <AnimatedSection
            direction="down"
            className="px-luxury pt-4 pb-2 flex-row justify-between items-center"
          >
            <View>
              <Text className="text-textSecondary text-xs font-black uppercase tracking-0.5 mb-1">
                {dayjs().hour() < 12
                  ? 'Good Morning'
                  : dayjs().hour() < 18
                    ? 'Good Afternoon'
                    : 'Good Evening'}
              </Text>
              <Text className="text-primary text-3xl font-bold tracking-tight">
                {(profile?.full_name || user?.user_metadata?.full_name)?.split(' ')[0] ||
                  user?.email?.split('@')[0] ||
                  'User'}
              </Text>
            </View>
            <View className="items-center justify-center">
              <Ionicons name="notifications-outline" size={20} color={THEME.colors.text} />
            </View>
          </AnimatedSection>

          <HomeSearchBar
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            useCurrentLocation={useCurrentLocation}
            setUseCurrentLocation={setUseCurrentLocation}
            userLocation={userLocation as unknown as Record<string, unknown>}
            locationLoading={locationLoading}
            onLocate={getUserLocation}
          />
          {/* 2. LIMITED-TIME DEALS */}
          <View className="mb-8">
            <View className="flex-row justify-between items-center px-luxury mb-4">
              <Text className="text-text text-lg font-bold tracking-tight uppercase">
                Limited-Time Deals
              </Text>
            </View>
            {isLoadingDeals ? (
              <View className="px-luxury flex-row">
                <LoadingSkeleton width={280} height={120} borderRadius={24} className="mr-4" />
                <LoadingSkeleton width={280} height={120} borderRadius={24} />
              </View>
            ) : filteredFlashDeals.length > 0 ? (
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                contentContainerStyle={{ paddingHorizontal: 24 }}
              >
                {filteredFlashDeals.map((deal, index) => (
                  <DealCard
                    key={deal.id}
                    item={deal as FlashDeal}
                    index={index}
                    onPress={() => handleBusinessPress(deal.business_id)}
                  />
                ))}
              </ScrollView>
            ) : (
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                contentContainerStyle={{ paddingHorizontal: 24 }}
              >
                {useCurrentLocation ? (
                  <Text className="text-textSecondary text-sm my-4">No nearby deals found.</Text>
                ) : (
                  (businesses && businesses.length > 0 ? businesses.slice(0, 3) : []).map(
                    (business, index) => {
                      const dummyTitles = [
                        '50% Off Premium Haircut',
                        'Flat ₹500 Off on Facials',
                        'Buy 1 Get 1 Beard Trim',
                      ];
                      const dummyDiscounts = ['50% OFF', '₹500 OFF', 'BOGO'];
                      return (
                        <DealCard
                          key={`dummy-${business.id}`}
                          item={
                            {
                              id: `dummy-${business.id}`,
                              business_id: business.id,
                              salon_name: business.salon_name,
                              title: dummyTitles[index] || 'Special Discount',
                              discount_text: dummyDiscounts[index] || 'OFFER',
                              expires_at: dayjs().add(24, 'hours').toISOString(),
                            } as FlashDeal
                          }
                          index={index}
                          onPress={() => handleBusinessPress(business.id)}
                        />
                      );
                    },
                  )
                )}
              </ScrollView>
            )}
          </View>

          {/* 3. NEARBY AVAILABLE NOW */}
          <View className="mb-8">
            <View className="flex-row justify-between items-center px-luxury mb-4">
              <Text className="text-text text-lg font-bold tracking-tight uppercase">
                Available Nearby Now
              </Text>
              <Pressable onPress={() => router.push('/(customer)/browse')}>
                <Text className="text-primary font-bold text-sm">See All</Text>
              </Pressable>
            </View>
            {isLoadingNearby ? (
              <View className="px-luxury flex-row">
                <LoadingSkeleton width={260} height={150} borderRadius={28} className="mr-4" />
                <LoadingSkeleton width={260} height={150} borderRadius={28} />
              </View>
            ) : filteredNearbySalons.length > 0 ? (
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                contentContainerStyle={{ paddingHorizontal: 24 }}
              >
                {filteredNearbySalons.map((salon, index) => (
                  <NearbySalonCard
                    key={salon.id}
                    item={salon}
                    index={index}
                    onPress={() => handleBusinessPress(salon.id)}
                  />
                ))}
              </ScrollView>
            ) : (
              <Text className="text-textSecondary px-luxury text-sm">
                {useCurrentLocation ? 'No nearby salons found.' : 'No available salons nearby.'}
              </Text>
            )}
          </View>

          {/* 4. RECENTLY BOOKED */}
          {filteredFavouriteSalons.length > 0 && (
            <View className="mb-8">
              <View className="flex-row justify-between items-center px-luxury mb-4">
                <Text className="text-text text-lg font-bold tracking-tight uppercase">
                  Recently Booked
                </Text>
              </View>
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                contentContainerStyle={{ paddingHorizontal: 24 }}
              >
                {filteredFavouriteSalons.map((item, index) => (
                  <BusinessCard
                    key={item.id}
                    item={item}
                    index={index}
                    onPress={() => handleBusinessPress(item.id)}
                  />
                ))}
              </ScrollView>
            </View>
          )}

          {/* 5. TRENDING SERVICES */}
          <View className="mb-8">
            <View className="flex-row justify-between items-center px-luxury mb-4">
              <Text className="text-text text-lg font-bold tracking-tight uppercase">
                Trending Services
              </Text>
            </View>
            {isLoadingTrending ? (
              <View className="px-luxury flex-row">
                <LoadingSkeleton width={180} height={140} borderRadius={24} className="mr-4" />
                <LoadingSkeleton width={180} height={140} borderRadius={24} />
              </View>
            ) : filteredTrendingServices.length > 0 ? (
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                contentContainerStyle={{ paddingHorizontal: 24 }}
              >
                {filteredTrendingServices.map((service, index) => (
                  <TrendingServiceCard
                    key={service.id}
                    item={service}
                    index={index}
                    onPress={() =>
                      service.business_id ? handleBusinessPress(service.business_id) : {}
                    }
                  />
                ))}
              </ScrollView>
            ) : (
              <Text className="text-textSecondary px-luxury text-sm">
                {useCurrentLocation
                  ? 'No nearby trending services.'
                  : 'Trending services will appear here.'}
              </Text>
            )}
          </View>
        </ScrollView>
      </SafeAreaView>
    </PremiumBackground>
  );
}

