source:
import { Ionicons } from '@expo/vector-icons';
import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  ScrollView,
  Pressable,
  ActivityIndicator,
  TextInput,
  KeyboardAvoidingView,
  Platform,
  Switch,
  Image,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';

import { AnimatedSection } from '@/components/animations/AnimatedSection';
import { GlassCard } from '@/components/ui/GlassCard';
import { PremiumBackground } from '@/components/ui/PremiumBackground';
import { PremiumButton } from '@/components/ui/PremiumButton';
import { useAuth } from '@/hooks/useAuth';
import { useModal } from '@/hooks/useModal';
import { useProfileImage } from '@/hooks/useProfileImage';
import { useProfileMedia } from '@/hooks/useProfileMedia';
import { apiService } from '@/services/api.service';
import { useAuthStore } from '@/store/auth.store';
import { THEME } from '@/theme/theme';

export default function CustomerProfileScreen() {
  const user = useAuthStore((s) => s.user);
  const profile = useAuthStore((s) => s.profile);
  const profileImageUrl = useAuthStore((s) => s.profileImageUrl);
  const refreshProfile = useAuthStore((s) => s.refreshProfile);
  const { signOut } = useAuth();
  const { showModal } = useModal();

  const { pickAndUpload, uploading } = useProfileImage();

  const { data: mediaUrl } = useProfileMedia(user?.id);

  const [loading, setLoading] = useState(!profile);

  const [updating, setUpdating] = useState(false);

  const [editMode, setEditMode] = useState(false);

  const [notificationsEnabled, setNotificationsEnabled] = useState(true);

  const [profileData, setProfileData] = useState<{
    profile?: {
      full_name?: string;
      phone_number?: string;
      user_type?: string;
      created_at?: string;
    } | null;
    user?: { email?: string; created_at?: string } | null;
    created_at?: string;
  } | null>(
    profile
      ? {
          profile: profile as unknown as {
            full_name?: string;
            phone_number?: string;
            user_type?: string;
            created_at?: string;
          },
        }
      : null,
  );

  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    full_name: profile?.full_name || '',
    phone_number: profile?.phone_number || '',
  });

  useEffect(() => {
    fetchProfile();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const fetchProfile = async () => {
    if (!profile) setLoading(true);

    try {
      const data = await apiService.getProfile();

      setProfileData(data as unknown as typeof profileData);

      if (data?.profile) {
        setFormData({
          full_name: data.profile.full_name || '',
          phone_number: data.profile.phone_number || '',
        });
      }
    } catch (err: unknown) {
      setError((err instanceof Error ? err.message : String(err)) || 'Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateProfile = async () => {
    if (!formData.full_name.trim()) {
      showModal({
        variant: 'error',
        title: 'Error',
        description: 'Full name is required',
      });
      return;
    }

    setUpdating(true);

    try {
      await apiService.updateProfile({
        full_name: formData.full_name,
        phone_number: formData.phone_number,
      });

      showModal({
        variant: 'success',
        title: 'Success',
        description: 'Profile updated successfully',
      });

      setEditMode(false);

      await fetchProfile();
      await refreshProfile();
    } catch (err: unknown) {
      showModal({
        variant: 'error',
        title: 'Update Failed',
        description:
          (err instanceof Error ? err.message : String(err)) || 'Could not update profile',
      });
    } finally {
      setUpdating(false);
    }
  };

  const handleCancel = () => {
    setEditMode(false);

    setFormData({
      full_name: profileData?.profile?.full_name || '',
      phone_number: profileData?.profile?.phone_number || '',
    });
  };

  const handleDeleteAccount = () => {
    showModal({
      variant: 'delete',
      title: 'Delete Account',
      description:
        'This action is permanent and will remove all your data after 30 days. Are you absolutely sure?',
      dismissible: true,
      actions: [
        {
          label: 'Delete Permanently',
          variant: 'danger',
          onPress: async () => {
            try {
              await apiService.deleteAccount('User requested deletion via mobile app');
              signOut();
            } catch (err: unknown) {
              showModal({
                variant: 'error',
                title: 'Error',
                description: 'Failed to delete account. Please try again.',
              });
            }
          },
        },
      ],
    });
  };

  const handleSignOut = () => {
    showModal({
      variant: 'signout',
      title: 'Sign Out',
      description: 'Are you sure you want to exit?',
      dismissible: true,
      actions: [
        {
          label: 'Sign Out',
          variant: 'primary',
          onPress: () => {
            signOut();
          },
        },
      ],
    });
  };

  const formatDate = (date: string) => {
    if (!date) return 'N/A';

    return new Date(date).toLocaleDateString('en-US', {
      weekday: 'long',
      day: 'numeric',
      month: 'long',
      year: 'numeric',
    });
  };

  if (loading) {
    return (
      <PremiumBackground>
        <View className="flex-1 justify-center items-center">
          <ActivityIndicator size="large" color={THEME.colors.primary} />
        </View>
      </PremiumBackground>
    );
  }

  return (
    <PremiumBackground>
      <SafeAreaView className="flex-1" edges={['left', 'right']}>
        <KeyboardAvoidingView
          behavior={Platform.OS === 'ios' ? 'padding' : undefined}
          className="flex-1"
        >
          <ScrollView
            showsVerticalScrollIndicator={false}
            contentContainerStyle={{
              paddingBottom: 40,
            }}
          >
            {/* Hero */}
            <View className="h-96 w-full relative">
              <Image
                source={{
                  uri: mediaUrl || profileImageUrl || undefined,
                }}
                className="w-full h-full"
                resizeMode="cover"
              />

              {/* Edit Image */}
              {editMode && (
                <Pressable
                  disabled={uploading}
                  onPress={async () => {
                    await pickAndUpload();
                  }}
                  className="absolute top-16 right-6 items-center justify-center shadow-lg"
                >
                  <Ionicons
                    name={uploading ? 'hourglass-outline' : 'camera-outline'}
                    size={24}
                    color={THEME.colors.primary}
                  />
                </Pressable>
              )}
            </View>

            {/* Header Card */}
            <View className="px-luxury -mt-10 mb-6">
              <AnimatedSection direction="up">
                <GlassCard className="p-2 border border-border bg-card shadow-sm rounded-3xl">
                  <View className="flex-row items-center justify-between mb-2">
                    <Text className="text-textSecondary text-xs font-black uppercase tracking-1">
                      Manage your account
                    </Text>

                    <View className="flex-row items-center">
                      <View className="w-2 h-2 rounded-full bg-success mr-2" />

                      <Text className="text-success text-xs font-black uppercase tracking-0.5">
                        Verified
                      </Text>
                    </View>
                  </View>

                  <Text className="text-text text-3xl font-extrabold tracking-tight mb-2">
                    {profileData?.profile?.full_name ||
                      profile?.full_name ||
                      user?.user_metadata?.full_name ||
                      'User'}
                  </Text>

                  <Text className="text-sm text-textSecondary font-medium">
                    Manage your profile, security, and personal preferences
                  </Text>
                </GlassCard>
              </AnimatedSection>
            </View>

            <View className="px-luxury">
              {/* Contact */}
              <AnimatedSection direction="up" delay={200}>
                <GlassCard className="p-2 border border-border bg-card shadow-sm rounded-3xl mb-6">
                  <View className="flex-row items-center justify-between mb-2">
                    <Text className="text-text text-xl font-bold tracking-tight uppercase">
                      Contact
                    </Text>

                    {!editMode && (
                      <Pressable
                        onPress={() => setEditMode(true)}
                        className="px-4 py-1 flex-row items-center"
                      >
                        <Ionicons name="create-outline" size={18} color={THEME.colors.primary} />

                        <Text className="text-sm uppercase tracking-wider text-primary font-bold ml-2">
                          Edit
                        </Text>
                      </Pressable>
                    )}
                  </View>

                  <View>
                    {/* Full Name */}
                    <View className="flex-row items-center justify-between py-5 border-b border-border">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-24">
                        Name
                      </Text>

                      <View className="flex-1 items-end">
                        {editMode ? (
                          <TextInput
                            value={formData.full_name}
                            onChangeText={(text) =>
                              setFormData((prev) => ({
                                ...prev,
                                full_name: text,
                              }))
                            }
                            placeholder="Enter full name"
                            placeholderTextColor={THEME.colors.textSecondary}
                            className="w-full border border-border bg-input rounded-2xl px-4 py-3 text-right text-base text-text font-semibold"
                          />
                        ) : (
                          <Text className="text-base text-text font-bold text-right">
                            {profileData?.profile?.full_name ||
                              profile?.full_name ||
                              user?.user_metadata?.full_name ||
                              'Not set'}
                          </Text>
                        )}
                      </View>
                    </View>

                    {/* Email */}
                    <View className="flex-row items-center justify-between py-5 border-b border-border">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-24">
                        Email
                      </Text>

                      <Text
                        className="text-base text-text font-bold text-right flex-1"
                        numberOfLines={1}
                      >
                        {profileData?.user?.email || user?.email || 'N/A'}
                      </Text>
                    </View>

                    {/* Phone */}
                    <View className="flex-row items-center justify-between py-5">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-24">
                        Phone
                      </Text>

                      <View className="flex-1 items-end">
                        {editMode ? (
                          <TextInput
                            value={formData.phone_number}
                            onChangeText={(text) =>
                              setFormData((prev) => ({
                                ...prev,
                                phone_number: text,
                              }))
                            }
                            placeholder="Enter phone number"
                            placeholderTextColor={THEME.colors.textSecondary}
                            keyboardType="phone-pad"
                            className="w-full border border-border bg-input rounded-2xl px-4 py-3 text-right text-base text-text font-semibold"
                          />
                        ) : (
                          <Text className="text-base text-text font-bold text-right">
                            {profileData?.profile?.phone_number ||
                              profile?.phone_number ||
                              'Not set'}
                          </Text>
                        )}
                      </View>
                    </View>
                  </View>
                </GlassCard>
              </AnimatedSection>

              {/* Edit Actions */}
              {editMode && (
                <AnimatedSection direction="up" delay={250}>
                  <View className="flex-row items-center gap-4 mb-6">
                    <View className="flex-1">
                      <PremiumButton
                        title={updating ? 'Saving...' : 'Save'}
                        onPress={handleUpdateProfile}
                        disabled={updating}
                        className="h-14 bg-primary rounded-2xl w-full"
                      />
                    </View>

                    <View className="flex-1">
                      <PremiumButton
                        title="Cancel"
                        variant="secondary"
                        onPress={handleCancel}
                        className="h-14 rounded-2xl border border-border bg-input w-full"
                        textClassName="text-textSecondary text-sm uppercase tracking-widest"
                      />
                    </View>
                  </View>
                </AnimatedSection>
              )}

              {/* Account */}
              <AnimatedSection direction="up" delay={300}>
                <GlassCard className="p-2 border border-border bg-card shadow-sm rounded-3xl mb-6">
                  <Text className="text-text text-xl font-bold tracking-tight uppercase mb-2">
                    Account
                  </Text>

                  <View>
                    {/* Account Type */}
                    <View className="flex-row items-center justify-between py-5 border-b border-border">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-32">
                        Type
                      </Text>

                      <View className="flex-1 items-end">
                        <Text className="text-base text-primary font-black text-right uppercase tracking-wide">
                          {profileData?.profile?.user_type === 'owner'
                            ? 'Business Owner'
                            : profileData?.profile?.user_type === 'both'
                              ? 'Customer & Owner'
                              : profileData?.profile?.user_type === 'admin'
                                ? 'Admin'
                                : 'Customer'}
                        </Text>
                      </View>
                    </View>

                    {/* Created */}
                    <View className="flex-row items-center justify-between py-5 border-b border-border">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-32">
                        Created
                      </Text>

                      <View className="flex-1 items-end">
                        <Text className="text-base text-text font-bold text-right">
                          {(() => {
                            const createdStr =
                              profileData?.profile?.created_at ||
                              profileData?.created_at ||
                              user?.created_at;
                            const createdDate = createdStr ? new Date(createdStr) : new Date();
                            return createdDate.toLocaleDateString('en-US', {
                              month: 'long',
                              day: 'numeric',
                              year: 'numeric',
                            });
                          })()}
                        </Text>
                      </View>
                    </View>

                    {/* Last Sign In */}
                    <View className="flex-row items-center justify-between py-5">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-32">
                        Last Login
                      </Text>

                      <View className="flex-1 items-end">
                        <Text className="text-base text-text font-bold text-right">
                          {(() => {
                            const date = new Date(
                              user?.last_sign_in_at || new Date().toISOString(),
                            );

                            const today = new Date();

                            const yesterday = new Date();
                            yesterday.setDate(today.getDate() - 1);

                            const isToday = date.toDateString() === today.toDateString();

                            const isYesterday = date.toDateString() === yesterday.toDateString();

                            if (isToday) return 'Today';

                            if (isYesterday) return 'Yesterday';

                            return date.toLocaleDateString('en-US', {
                              month: 'long',
                              day: 'numeric',
                              year: 'numeric',
                            });
                          })()}
                        </Text>
                      </View>
                    </View>
                  </View>
                </GlassCard>
              </AnimatedSection>

              {/* Preferences */}
              <AnimatedSection direction="up" delay={400}>
                <GlassCard className="p-2 border border-border bg-card shadow-sm rounded-3xl mb-6">
                  <Text className="text-text text-xl font-bold tracking-tight uppercase mb-6">
                    Preferences
                  </Text>

                  <View className="flex-row items-center justify-between">
                    <View className="flex-row items-center flex-1 ml--3.75 mr-1.25">
                      <View className="w-12 h-12 rounded-full items-center justify-center">
                        <Ionicons
                          name="notifications-outline"
                          size={22}
                          color={THEME.colors.textSecondary}
                        />
                      </View>

                      <Text className="text-text text-base font-bold">Notifications</Text>
                    </View>

                    <Switch
                      value={notificationsEnabled}
                      onValueChange={setNotificationsEnabled}
                      trackColor={{
                        false: THEME.colors.border,
                        true: THEME.colors.primary,
                      }}
                      thumbColor={THEME.colors.text}
                    />
                  </View>
                </GlassCard>
              </AnimatedSection>

              {/* Danger */}
              <AnimatedSection direction="up" delay={500}>
                <GlassCard className="p-2 border border-error/30 bg-error/5 rounded-3xl mb-6">
                  <Text className="text-error text-xl font-black uppercase tracking-0.5 mb-3">
                    Danger Zone
                  </Text>

                  <Text className="text-sm leading-6 text-textSecondary font-medium mb-5">
                    Permanently remove your account and all associated data. This action cannot be
                    undone after 30 days.
                  </Text>

                  <Pressable
                    onPress={handleDeleteAccount}
                    className="flex-row items-center justify-center border border-error/40 bg-error/5 rounded-2xl h-14 active:bg-error/20"
                  >
                    <Text className="text-error font-black text-sm uppercase tracking-0.5">
                      Delete Account
                    </Text>
                  </Pressable>
                </GlassCard>
              </AnimatedSection>

              {/* Sign Out */}
              <AnimatedSection direction="up" delay={600}>
                <Pressable
                  onPress={handleSignOut}
                  className="bg-input border border-border rounded-2xl h-14 items-center justify-center active:bg-card mb-10"
                >
                  <Text className="text-text font-bold text-sm uppercase tracking-widest">
                    Sign Out
                  </Text>
                </Pressable>
              </AnimatedSection>

              {error && <Text className="text-error text-center mb-6 font-bold">{error}</Text>}
            </View>
          </ScrollView>
        </KeyboardAvoidingView>
      </SafeAreaView>
    </PremiumBackground>
  );
}

import { Ionicons } from '@expo/vector-icons';
import { Image } from 'expo-image';
import { useLocalSearchParams, router } from 'expo-router';
import React, { useState, useEffect } from 'react';
import { View, Text, ScrollView, Pressable, Linking, ActivityIndicator } from 'react-native';

import { AnimatedSection } from '@/components/animations/AnimatedSection';
import { Avatar } from '@/components/ui/Avatar';
import { GlassCard } from '@/components/ui/GlassCard';
import { PremiumBackground } from '@/components/ui/PremiumBackground';
import { PremiumButton } from '@/components/ui/PremiumButton';
import { useBusinessDetail } from '@/hooks/useBusinesses';
import { useModal } from '@/hooks/useModal';
import { useProfileMedia } from '@/hooks/useProfileMedia';
import { apiService } from '@/services/api.service';
import { useBookingStore } from '@/store/booking.store';
import { THEME } from '@/theme/theme';
import { isValidImageUrl } from '@/utils/image';
import { getShopStatus } from '@/utils/time';

import type { Service } from '@/types/business.types';

export default function SalonDetailsScreen() {
  const { id } = useLocalSearchParams();
  const { data: business, isLoading: businessLoading, error } = useBusinessDetail(id as string);
  const setBusiness = useBookingStore((s) => s.setBusiness);
  const setSelectedServices = useBookingStore((s) => s.setSelectedServices);
  const [localSelectedServices, setLocalSelectedServices] = useState<Service[]>([]);
  const { showModal } = useModal();

  // States for API fetched data
  const [services, setServices] = useState<Service[]>([]);
  const [reviewsData, setReviewsData] = useState<{
    reviews: {
      id: string;
      rating?: number | string;
      customer?: { full_name?: string; avatar_url?: string };
      customer_name?: string;
      name?: string;
      comment?: string;
      created_at?: string;
      date?: string;
      user_id?: string;
    }[];
  } | null>(null);
  const [photos, setPhotos] = useState<string[]>([]);
  const [loadingExtra, setLoadingExtra] = useState(false);
  const { data: ownerImage } = useProfileMedia(business?.owner_user_id ?? null);
  useEffect(() => {
    if (!business?.id) return;

    const fetchExtraData = async () => {
      try {
        setLoadingExtra(true);

        // 1. Fetch real public services
        const svc = await apiService.getPublicServices(business.id);
        setServices(svc as unknown as Service[]);

        // 2. Fetch real reviews
        const rev = await apiService.getReviews(business.id);
        setReviewsData(rev as unknown as typeof reviewsData);

        // 3. Fetch real media and signed URLs
        const media = await apiService.getBusinessMedia(business.id);
        const items = media?.items || [];
        if (items.length > 0) {
          const urls = await Promise.all(
            items.map(async (item: { id: string; [key: string]: unknown }) => {
              try {
                const signed = await apiService.getSignedUrl(item.id);
                return signed?.url || null;
              } catch {
                return null;
              }
            }),
          );
          setPhotos(urls.filter((u): u is string => isValidImageUrl(u)));
        } else {
          setPhotos([]);
        }
      } catch (err) {
        console.error('Error fetching salon details extra data:', err);
      } finally {
        setLoadingExtra(false);
      }
    };

    fetchExtraData();
  }, [business?.id]);

  if (businessLoading) {
    return (
      <PremiumBackground>
        <View className="flex-1 items-center justify-center">
          <ActivityIndicator size="large" color={THEME.colors.primary} />
          <Text className="text-textSecondary font-medium mt-4 font-semibold">
            Loading salon details...
          </Text>
        </View>
      </PremiumBackground>
    );
  }

  if (error || !business) {
    return (
      <PremiumBackground>
        <View className="flex-1 items-center justify-center px-6">
          <Ionicons name="alert-circle-outline" size={64} color={THEME.colors.error} />
          <Text className="text-text text-xl font-bold mt-4 text-center">Salon Not Found</Text>
          <Text className="text-textSecondary text-center mt-2 mb-6">
            We couldn't retrieve the details for this business.
          </Text>
          <PremiumButton title="Go Back" onPress={() => router.back()} className="w-48 h-12" />
        </View>
      </PremiumBackground>
    );
  }

  // Guard: suspended or soft-deleted businesses must not be accessible
  if (business.suspended === true || business.deleted_at != null) {
    return (
      <PremiumBackground>
        <View className="flex-1 items-center justify-center px-6">
          <Ionicons name="ban-outline" size={64} color={THEME.colors.textSecondary} />
          <Text className="text-text text-xl font-bold mt-4 text-center">Business Unavailable</Text>
          <Text className="text-textSecondary text-center mt-2 mb-6">
            This business is no longer available for bookings.
          </Text>
          <PremiumButton
            title="Browse Salons"
            onPress={() => router.replace('/(customer)/browse')}
            className="w-48 h-12"
          />
        </View>
      </PremiumBackground>
    );
  }

  const handleSelectService = (service: Service) => {
    setLocalSelectedServices((prev) => {
      const exists = prev.some((s) => s.id === service.id);
      if (exists) {
        return prev.filter((s) => s.id !== service.id);
      } else {
        return [...prev, service];
      }
    });
  };

  const handleBookNow = (preSelectedService?: Service) => {
    setBusiness(business);
    if (preSelectedService) {
      setSelectedServices([preSelectedService]);
    } else if (localSelectedServices.length > 0) {
      setSelectedServices(localSelectedServices);
    } else if (services.length > 0) {
      // Default to first service if none selected
      setSelectedServices([services[0]]);
    }

    router.push(`/(customer)/book/${business.id}`);
  };
  const handleCall = (phoneNumber?: string) => {
    if (!phoneNumber) return;

    Linking.openURL(`tel:${phoneNumber}`).catch(() => {
      showModal({
        variant: 'error',
        title: 'Error',
        description: 'Unable to open phone dialer.',
      });
    });
  };

  const handleContactWhatsApp = () => {
    if (business.whatsapp_number) {
      const formattedNum = business.whatsapp_number.replace(/[^0-9]/g, '');
      Linking.openURL(`https://wa.me/${formattedNum}`).catch(() => {
        Linking.openURL(`tel:${business.whatsapp_number}`);
      });
    }
  };

  const shopStatus = getShopStatus(business?.opening_time, business?.closing_time);
  const shopIsOpen = shopStatus.isOpen;

  // Normalise reviews. Backend may return either:
  // - customer: { full_name } and/or created_at
  // - customer_name (already anonymized) and/or created_at
  const hasRealReviews = !!(reviewsData?.reviews && reviewsData.reviews.length > 0);
  const reviewsList = hasRealReviews
    ? reviewsData.reviews.map(
        (r: {
          id: string;
          rating?: number | string;
          customer?: { full_name?: string; avatar_url?: string };
          customer_name?: string;
          name?: string;
          comment?: string;
          created_at?: string;
          date?: string;
          user_id?: string;
          [key: string]: unknown;
        }) => {
          const rawRating = typeof r.rating === 'number' ? r.rating : Number(r.rating);
          const rating = Number.isFinite(rawRating) && rawRating > 0 ? rawRating : 0;

          const name = r.customer?.full_name || r.customer_name || r.name || 'Guest User';

          const comment = (r.comment ?? '') as string;

          const createdAt = r.created_at || r.date;
          const date = createdAt
            ? new Date(createdAt).toLocaleDateString('en-US', {
                month: 'short',
                day: 'numeric',
                year: 'numeric',
              })
            : 'Recently';

          return {
            id: r.id,
            name,
            rating,
            comment,
            date,
            user_id: r.user_id,
            avatar_url: r.customer?.avatar_url,
          };
        },
      )
    : [];

  // Ratings calculation based on API response

  const displayRatingAvg =
    business.rating_avg && Number(business.rating_avg) > 0
      ? Number(business.rating_avg).toFixed(1)
      : 'New';
  const displayReviewCount = business.review_count;

  // Compute total selected details
  const totalSelectedPrice = localSelectedServices.reduce(
    (sum, s) => sum + (Number(s.price) || 0),
    0,
  );
  const totalSelectedDuration = localSelectedServices.reduce(
    (sum, s) => sum + (Number(s.duration) || 30),
    0,
  );

  return (
    <PremiumBackground>
      <ScrollView
        className="flex-1"
        showsVerticalScrollIndicator={false}
        contentContainerStyle={{ paddingBottom: 160 }}
      >
        {/* Hero Header */}
        <View className="h-96 w-full relative">
          {ownerImage ? (
            <Image
              className="w-full h-full"
              source={{ uri: ownerImage }}
              contentFit="cover"
              transition={300}
              cachePolicy="memory-disk"
            />
          ) : (
            <Avatar
              userId={business.owner_user_id}
              name={business.salon_name}
              size={400}
              type="business"
              className="w-full h-full"
            />
          )}
          <View className="absolute inset-0 bg-black/30" />

          <Pressable
            onPress={() => router.back()}
            className="absolute top-16 left-6 w-12 h-12 rounded-full items-center justify-center shadow-lg"
          >
            <Ionicons name="arrow-back" size={24} color="white" />
          </Pressable>
        </View>

        <View className="px-luxury -mt-10">
          <AnimatedSection direction="up">
            <GlassCard className="p-2 bg-card shadow-sm rounded-3xl">
              {/* Name and Rating */}
              <View className="flex-row justify-between items-start mb-4">
                <View className="flex-1 mr-4">
                  <Text className="text-text text-3xl font-extrabold tracking-tight mb-1">
                    {business.salon_name}
                  </Text>
                  <View className="flex-row items-center">
                    <Ionicons
                      name="location-outline"
                      size={16}
                      color={THEME.colors.textSecondary}
                    />
                    <Text className="text-textSecondary ml-1.5 text-sm" numberOfLines={1}>
                      {business.address || 'Address not listed'}
                    </Text>
                  </View>
                </View>
                <View className="items-end bg-border px-3 py-1.5 rounded-xl flex-row items-center shadow-sm">
                  <View className="flex-row items-center">
                    <Ionicons
                      className="mr-1"
                      name={
                        business.rating_avg && Number(business.rating_avg) > 0
                          ? 'star'
                          : 'star-outline'
                      }
                      size={16}
                      color={
                        business.rating_avg && Number(business.rating_avg) > 0
                          ? THEME.colors.gold
                          : THEME.colors.textSecondary
                      }
                    />

                    <Text className="text-text text-sm font-semibold">
                      {business.rating_avg ? Number(business.rating_avg).toFixed(1) : '0.0'}
                    </Text>
                  </View>
                  {displayReviewCount > 0 ? (
                    <Text className="text-textSecondary text-xs ml-1">({displayReviewCount})</Text>
                  ) : null}
                </View>
              </View>

              {/* Status & Hours */}
              <View className="flex-row items-center mb-2 border-t border-border pt-2 rounded-2xl">
                <Ionicons name="time-outline" size={18} color={THEME.colors.primary} />
                <Text className="text-text font-bold ml-2 text-xs">
                  Hours: {business.opening_time || '09:00 AM'} -{' '}
                  {business.closing_time || '09:00 PM'}
                </Text>
                <View
                  className="w-1.5 h-1.5 rounded-full ml-auto mr-1"
                  style={[
                    {
                      backgroundColor: shopIsOpen ? THEME.colors.success : THEME.colors.error,
                    },
                  ]}
                />
                <Text
                  className={
                    shopIsOpen ? 'text-success font-bold text-xs' : 'text-error font-bold text-xs'
                  }
                >
                  {shopIsOpen ? 'Open Now' : 'Closed'}
                </Text>
              </View>

              {/* Owner Info & Contact Row */}
              <View className="border-t border-border pt-6">
                <Text className="text-textSecondary text-xs font-bold uppercase tracking-wider mb-3">
                  Owner Info
                </Text>
                <View className="flex-row items-center justify-between">
                  <View className="flex-row items-center">
                    <Avatar
                      userId={business.owner_user_id}
                      name={business.owner_name || 'Owner'}
                      size={42}
                      type="business"
                      className="w-11 h-11 rounded-full mr-3 shadow-sm"
                    />
                    <View>
                      <Text className="text-text font-bold text-base">
                        {business.owner_name || 'Salon Owner'}
                      </Text>
                      <Text className="text-textSecondary text-xs">Verified Business Partner</Text>
                    </View>
                  </View>
                  <Pressable
                    onPress={() => handleCall(business.whatsapp_number)}
                    className="flex-row items-center px-4 py-2.5 rounded-full shadow-sm"
                  >
                    <Ionicons name="call-outline" size={24} color={THEME.colors.primary} />
                  </Pressable>
                  {business.whatsapp_number ? (
                    <Pressable
                      onPress={handleContactWhatsApp}
                      className="flex-row items-center px-4 py-2.5 rounded-full shadow-sm"
                    >
                      <Ionicons name="logo-whatsapp" size={25} color="#25D366" />
                    </Pressable>
                  ) : null}
                </View>
              </View>
            </GlassCard>
          </AnimatedSection>
        </View>

        {/* Services Section */}
        <View className="px-luxury mt-8">
          <Text className="text-text text-xl font-bold mb-4 tracking-tight uppercase">
            Services
          </Text>
          {loadingExtra ? (
            <View className="bg-card  rounded-3xl p-8 items-center justify-center">
              <ActivityIndicator size="small" color={THEME.colors.primary} />
              <Text className="text-textSecondary text-xs mt-2 font-bold">
                Scanning services...
              </Text>
            </View>
          ) : services.length === 0 ? (
            <View className="bg-card  rounded-3xl p-6 items-center">
              <Ionicons name="construct-outline" size={32} color={THEME.colors.textSecondary} />
              <Text className="text-textSecondary text-sm mt-2 text-center">
                No services currently listed for this salon.
              </Text>
            </View>
          ) : (
            <View className="gap-y-3">
              {services.map((service: Service) => {
                const isSelected = localSelectedServices.some((s) => s.id === service.id);
                return (
                  <Pressable
                    key={service.id}
                    onPress={() => handleSelectService(service)}
                    className={`bg-card border p-5 rounded-3xl flex-row items-center ${
                      isSelected ? 'border-primary bg-primary/10 shadow-sm' : 'border-border'
                    }`}
                  >
                    <View className="flex-1 mr-4">
                      <Text className="text-text font-bold text-lg mb-1">{service.name}</Text>
                      {service.description ? (
                        <Text className="text-textSecondary text-sm mb-2" numberOfLines={2}>
                          {service.description}
                        </Text>
                      ) : null}
                      <View className="flex-row items-center">
                        <Ionicons
                          name="time-outline"
                          size={14}
                          color={THEME.colors.textSecondary}
                        />
                        <Text className="text-textSecondary text-xs font-semibold ml-1 mr-4">
                          {service.duration} mins
                        </Text>
                        <Ionicons
                          name="cash-outline"
                          size={14}
                          color={THEME.colors.textSecondary}
                        />
                        <Text className="text-text text-xs font-bold ml-1">₹{service.price}</Text>
                      </View>
                    </View>
                    <Pressable
                      onPress={(e) => {
                        e.stopPropagation();
                        handleBookNow(service);
                      }}
                      className="bg-primary px-4 py-2 rounded-xl items-center justify-center"
                    >
                      <Text className="text-background font-bold text-xs">Book</Text>
                    </Pressable>
                  </Pressable>
                );
              })}
            </View>
          )}
        </View>

        {/* Gallery Section */}
        {photos.length > 0 && (
          <View className="px-luxury mt-10">
            <Text className="text-text text-xl font-bold mb-4 tracking-tight uppercase">
              Photos
            </Text>

            {/* 2 Column Grid */}
            <View className="flex-row flex-wrap justify-between">
              {photos.map((url, i) => (
                <View
                  key={i}
                  className="flex-1 h-44 bg-card rounded-3xl  overflow-hidden shadow-sm mb-4"
                >
                  <Image source={{ uri: url }} className="w-full h-full" resizeMode="cover" />
                </View>
              ))}
            </View>
          </View>
        )}

        {/* Reviews Section */}
        <View className="px-luxury mt-10">
          <Text className="text-text text-xl font-bold mb-4 tracking-tight uppercase">
            Recent Reviews
          </Text>
          <View className="gap-y-3">
            {reviewsList.length > 0 ? (
              reviewsList.map(
                (rev: {
                  id: string;
                  rating: number;
                  date: string;
                  comment: string;
                  user_id?: string;
                  avatar_url?: string;
                }) => (
                  <View key={rev.id} className="bg-card  rounded-3xl p-5 shadow-sm">
                    <View className="flex-row justify-between items-center mb-2">
                      <View className="flex-row items-center">
                        {[1, 2, 3, 4, 5].map((star) => (
                          <Ionicons
                            className="mr-0.5"
                            key={star}
                            name={star <= Math.round(rev.rating) ? 'star' : 'star-outline'}
                            size={16}
                            color="#FACC15"
                          />
                        ))}
                        <Text className="text-text font-extrabold text-xs ml-2">
                          {Number.isFinite(rev.rating) ? rev.rating.toFixed(1) : '0.0'}
                        </Text>
                      </View>
                      <Text className="text-textSecondary text-xs">{rev.date}</Text>
                    </View>
                    {rev.comment ? (
                      <Text className="text-textSecondary text-sm leading-relaxed mt-2 font-medium">
                        {rev.comment}
                      </Text>
                    ) : null}
                  </View>
                ),
              )
            ) : (
              <View className="bg-card  rounded-3xl p-6 items-center">
                <Ionicons name="star-outline" size={32} color={THEME.colors.textSecondary} />
                <Text className="text-textSecondary text-sm mt-2 text-center font-medium">
                  No reviews or ratings yet.
                </Text>
              </View>
            )}
          </View>
        </View>
      </ScrollView>

      {/* Sticky Bottom Booking Button */}
      <View className="absolute bottom-0 left-0 right-0 bg-card border-t border-border px-6 pt-6 pb-6 flex-row justify-between items-center shadow-lg">
        <View className="flex-1 mr-4">
          <Text className="text-textSecondary text-xs font-bold uppercase tracking-wider">
            {localSelectedServices.length > 0
              ? `${localSelectedServices.length} Selected`
              : 'Booking Flow'}
          </Text>
          <Text className="text-text font-extrabold text-base" numberOfLines={1}>
            {localSelectedServices.length > 0
              ? localSelectedServices.map((s) => s.name).join(', ')
              : 'Choose Service(s)'}
          </Text>
          {localSelectedServices.length > 0 ? (
            <Text className="text-primary font-extrabold text-lg">
              ₹{totalSelectedPrice}{' '}
              <Text className="text-textSecondary font-semibold text-xs">
                / {totalSelectedDuration}m
              </Text>
            </Text>
          ) : null}
        </View>

        <PremiumButton
          title={localSelectedServices.length > 0 ? 'Book Slot' : 'Reserve Slot'}
          onPress={() => handleBookNow()}
          className="flex-1 h-10 rounded-2xl"
        />
      </View>
    </PremiumBackground>
  );
}

