import { Ionicons } from '@expo/vector-icons';
import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  ScrollView,
  Pressable,
  ActivityIndicator,
  TextInput,
  KeyboardAvoidingView,
  Platform,
  Image,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';

import { AnimatedSection } from '@/components/animations/AnimatedSection';
import { Avatar } from '@/components/ui/Avatar';
import { GlassCard } from '@/components/ui/GlassCard';
import { PremiumBackground } from '@/components/ui/PremiumBackground';
import { PremiumButton } from '@/components/ui/PremiumButton';
import { useProfileImage } from '@/features/shared/hooks/useProfileImage';
import { useAuth } from '@/hooks/useAuth';
import { useModal } from '@/hooks/useModal';
import { useProfileMedia } from '@/hooks/useProfileMedia';
import { apiService } from '@/services/api.service';
import { useAuthStore } from '@/store/auth.store';
import { THEME } from '@/theme/theme';
import { isValidImageUrl } from '@/utils/image';
// New UI Components

export default function OwnerProfileScreen() {
  const { signOut } = useAuth();
  const user = useAuthStore((s) => s.user);
  const profile = useAuthStore((s) => s.profile);
  const profileImageUrl = useAuthStore((s) => s.profileImageUrl);
  const { pickAndUpload, uploading } = useProfileImage();
  const { data: mediaUrl } = useProfileMedia(user?.id);
  const { showModal } = useModal();

  const [loading, setLoading] = useState(!profile);
  const [updating, setUpdating] = useState(false);
  const [editMode, setEditMode] = useState(false);

  const [profileData, setProfileData] = useState<{
    profile?: {
      full_name?: string;
      phone_number?: string;
      user_type?: string;
      created_at?: string;
    } | null;
    user?: { email?: string; created_at?: string } | null;
    created_at?: string;
  } | null>(
    profile
      ? {
          profile: profile as unknown as {
            full_name?: string;
            phone_number?: string;
            user_type?: string;
            created_at?: string;
          },
        }
      : null,
  );
  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    full_name: profile?.full_name || '',
    phone_number: profile?.phone_number || '',
  });

  useEffect(() => {
    fetchProfile();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const fetchProfile = async () => {
    if (!profile) setLoading(true);

    try {
      const data = await apiService.getProfile();

      setProfileData(data as unknown as typeof profileData);

      if (data?.profile) {
        setFormData({
          full_name: data.profile.full_name || '',
          phone_number: data.profile.phone_number || '',
        });
      }
    } catch (err: unknown) {
      setError((err instanceof Error ? err.message : String(err)) || 'Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateProfile = async () => {
    if (!formData.full_name.trim()) {
      showModal({
        variant: 'error',
        title: 'Error',
        description: 'Full name is required',
      });
      return;
    }

    setUpdating(true);

    try {
      await apiService.updateProfile({
        full_name: formData.full_name,
        phone_number: formData.phone_number,
      });

      showModal({
        variant: 'success',
        title: 'Success',
        description: 'Profile updated successfully',
      });
      setEditMode(false);
      fetchProfile();
    } catch (err: unknown) {
      showModal({
        variant: 'error',
        title: 'Update Failed',
        description:
          (err instanceof Error ? err.message : String(err)) || 'Could not update profile',
      });
    } finally {
      setUpdating(false);
    }
  };

  const handleCancel = () => {
    setEditMode(false);
    setFormData({
      full_name: profileData?.profile?.full_name || '',
      phone_number: profileData?.profile?.phone_number || '',
    });
  };

  const handleDeleteAccount = () => {
    showModal({
      variant: 'delete',
      title: 'Delete Account',
      description:
        'This action is permanent and will remove all your data after 30 days. Are you absolutely sure?',
      dismissible: true,
      actions: [
        {
          label: 'Delete Permanently',
          variant: 'danger',
          onPress: async () => {
            try {
              await apiService.deleteAccount('User requested deletion via mobile app');
              signOut();
            } catch (err: unknown) {
              showModal({
                variant: 'error',
                title: 'Error',
                description: 'Failed to delete account. Please try again.',
              });
            }
          },
        },
      ],
    });
  };

  const handleSignOut = () => {
    showModal({
      variant: 'signout',
      title: 'Sign Out',
      description: 'Are you sure you want to exit?',
      dismissible: true,
      actions: [
        {
          label: 'Sign Out',
          variant: 'primary',
          onPress: () => signOut(),
        },
      ],
    });
  };

  const formatDate = (date: string) => {
    if (!date) return 'N/A';
    return new Date(date).toLocaleDateString('en-US', {
      weekday: 'long',
      day: 'numeric',
      month: 'long',
      year: 'numeric',
    });
  };

  if (loading) {
    return (
      <PremiumBackground>
        <View className="flex-1 justify-center items-center">
          <ActivityIndicator size="large" color={THEME.colors.primary} />
        </View>
      </PremiumBackground>
    );
  }

  return (
    <PremiumBackground>
      <SafeAreaView className="flex-1" edges={['left', 'right']}>
        <KeyboardAvoidingView
          behavior={Platform.OS === 'ios' ? 'padding' : undefined}
          className="flex-1"
        >
          <ScrollView
            showsVerticalScrollIndicator={false}
            contentContainerStyle={{
              paddingBottom: 40,
            }}
          >
            <View className="h-96 w-full relative">
              {isValidImageUrl(mediaUrl || profileImageUrl) ? (
                <Image
                  source={{
                    uri: mediaUrl || profileImageUrl || undefined,
                  }}
                  className="w-full h-full"
                  resizeMode="cover"
                />
              ) : (
                <Avatar
                  userId={user?.id}
                  name={
                    profileData?.profile?.full_name ||
                    profile?.full_name ||
                    user?.user_metadata?.full_name ||
                    'User'
                  }
                  size={400}
                  type="customer"
                  className="w-full h-full"
                />
              )}

              {/* Edit Image */}
              {editMode && (
                <Pressable
                  disabled={uploading}
                  onPress={async () => {
                    await pickAndUpload();
                  }}
                  className="absolute top-16 right-6 items-center justify-center shadow-lg"
                >
                  <Ionicons
                    name={uploading ? 'hourglass-outline' : 'camera-outline'}
                    size={24}
                    color={THEME.colors.primary}
                  />
                </Pressable>
              )}
            </View>

            {/* Profile Info Overlapping Card */}
            <View className="px-luxury -mt-10 mb-6">
              <AnimatedSection direction="up">
                <GlassCard className="p-2 border border-border bg-card shadow-sm rounded-3xl">
                  <View className="flex-row items-center justify-between mb-1">
                    <Text className="text-textSecondary text-xs font-black uppercase tracking-1">
                      Manage your account
                    </Text>

                    <View className="flex-row items-center">
                      <View className="w-2 h-2 rounded-full bg-success mr-2" />

                      <Text className="text-success text-xs font-black uppercase tracking-0.5">
                        Verified
                      </Text>
                    </View>
                  </View>
                  <Text className="text-text text-3xl font-extrabold tracking-tight mb-2">
                    {profileData?.profile?.full_name || 'User'}
                  </Text>
                  <Text className="text-sm text-textSecondary font-medium">
                    Manage your profile, security, and personal preferences
                  </Text>
                </GlassCard>
              </AnimatedSection>
            </View>

            <View className="px-luxury">
              {/* Contact Card */}
              <AnimatedSection direction="up" delay={200}>
                <GlassCard className="p-2 border border-border bg-card shadow-sm rounded-3xl mb-6">
                  <View className="flex-row items-center justify-between mb-6">
                    <Text className="text-text text-xl font-bold tracking-tight uppercase">
                      Contact
                    </Text>

                    {!editMode && (
                      <Pressable
                        onPress={() => setEditMode(true)}
                        className="px-4 py-2 active:bg-input flex-row items-center"
                      >
                        <Ionicons
                          name="create-outline"
                          size={14}
                          color={THEME.colors.primary}
                          className="mr-1"
                        />
                        <Text className="text-sm uppercase tracking-wider text-primary font-bold ml-1">
                          Edit
                        </Text>
                      </Pressable>
                    )}
                  </View>

                  <View>
                    {/* Full Name */}
                    <View className="flex-row items-center justify-between py-5 border-b border-border">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-24">
                        Name
                      </Text>

                      <View className="flex-1 items-end">
                        {editMode ? (
                          <TextInput
                            value={formData.full_name}
                            onChangeText={(text) =>
                              setFormData((prev) => ({
                                ...prev,
                                full_name: text,
                              }))
                            }
                            placeholder="Enter full name"
                            placeholderTextColor={THEME.colors.textSecondary}
                            className="w-full border border-border bg-input rounded-2xl px-4 py-3 text-right text-base text-text font-semibold"
                          />
                        ) : (
                          <Text className="text-base text-text font-bold text-right">
                            {profileData?.profile?.full_name || 'Not set'}
                          </Text>
                        )}
                      </View>
                    </View>

                    {/* Email */}
                    <View className="flex-row items-center justify-between py-5 border-b border-border">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-24">
                        Email
                      </Text>

                      <Text
                        className="text-base text-text font-bold text-right flex-1"
                        numberOfLines={1}
                      >
                        {profileData?.user?.email || user?.email || 'N/A'}
                      </Text>
                    </View>

                    {/* Phone */}
                    <View className="flex-row items-center justify-between py-5">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-24">
                        Phone
                      </Text>

                      <View className="flex-1 items-end">
                        {editMode ? (
                          <TextInput
                            value={formData.phone_number}
                            onChangeText={(text) =>
                              setFormData((prev) => ({
                                ...prev,
                                phone_number: text,
                              }))
                            }
                            placeholder="Enter phone number"
                            placeholderTextColor={THEME.colors.textSecondary}
                            keyboardType="phone-pad"
                            className="w-full border border-border bg-input rounded-2xl px-4 py-3 text-right text-base text-text font-semibold"
                          />
                        ) : (
                          <Text className="text-base text-text font-bold text-right">
                            {profileData?.profile?.phone_number || 'Not set'}
                          </Text>
                        )}
                      </View>
                    </View>
                  </View>
                </GlassCard>
              </AnimatedSection>

              {/* Edit Actions */}
              {editMode && (
                <AnimatedSection direction="up" delay={250}>
                  <View className="flex-row gap-4 mb-6">
                    <View className="flex-1">
                      <PremiumButton
                        title={updating ? 'Saving...' : 'Save'}
                        onPress={handleUpdateProfile}
                        disabled={updating}
                        className="h-12 bg-primary rounded-2xl"
                      />
                    </View>

                    <PremiumButton
                      title="Cancel"
                      variant="secondary"
                      onPress={handleCancel}
                      className="flex-1 h-12 rounded-2xl border border-border bg-input"
                      textClassName="text-textSecondary text-sm uppercase tracking-widest"
                    />
                  </View>
                </AnimatedSection>
              )}

              {/* Account Card */}
              <AnimatedSection direction="up" delay={300}>
                <GlassCard className="p-2 border border-border bg-card shadow-sm rounded-3xl mb-6">
                  <Text className="text-text text-xl font-bold tracking-tight uppercase mb-6">
                    Account
                  </Text>

                  <View>
                    <View className="flex-row items-center justify-between py-5 border-b border-border">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-32">
                        Type
                      </Text>
                      <View className="flex-1 items-end">
                        <Text className="text-base text-primary font-black text-right uppercase tracking-wide">
                          {profileData?.profile?.user_type === 'owner'
                            ? 'Business Owner'
                            : profileData?.profile?.user_type === 'both'
                              ? 'Customer & Owner'
                              : profileData?.profile?.user_type === 'admin'
                                ? 'Admin'
                                : 'Business Owner'}
                        </Text>
                      </View>
                    </View>

                    <View className="flex-row items-center justify-between py-5 border-b border-border">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-32">
                        Created
                      </Text>
                      <View className="flex-1 items-end">
                        <Text className="text-base text-text font-bold text-right">
                          {(() => {
                            const createdStr =
                              profileData?.profile?.created_at ||
                              profileData?.created_at ||
                              user?.created_at;
                            const createdDate = createdStr ? new Date(createdStr) : new Date();
                            return createdDate.toLocaleDateString('en-US', {
                              month: 'long',
                              day: 'numeric',
                              year: 'numeric',
                            });
                          })()}
                        </Text>
                      </View>
                    </View>

                    <View className="flex-row items-center justify-between py-5">
                      <Text className="text-textSecondary text-xs uppercase tracking-0.5 font-black w-32">
                        Last Login
                      </Text>
                      <View className="flex-1 items-end">
                        <Text className="text-base text-text font-bold text-right">
                          {(() => {
                            const date = new Date(
                              user?.last_sign_in_at || new Date().toISOString(),
                            );
                            const today = new Date();
                            const yesterday = new Date();
                            yesterday.setDate(today.getDate() - 1);

                            if (date.toDateString() === today.toDateString()) return 'Today';
                            if (date.toDateString() === yesterday.toDateString())
                              return 'Yesterday';

                            return date.toLocaleDateString('en-US', {
                              month: 'long',
                              day: 'numeric',
                              year: 'numeric',
                            });
                          })()}
                        </Text>
                      </View>
                    </View>
                  </View>
                </GlassCard>
              </AnimatedSection>

              {/* Danger Zone */}
              <AnimatedSection direction="up" delay={500}>
                <GlassCard className="p-2 border border-error/30 bg-error/5 rounded-3xl mb-6">
                  <View className="flex-row items-center mb-3">
                    <Text className="text-error text-xl font-black uppercase tracking-0.5">
                      Danger Zone
                    </Text>
                  </View>

                  <Text className="text-sm leading-6 text-textSecondary font-medium mb-5">
                    Permanently remove your account and all associated data. This action cannot be
                    undone after 30 days.
                  </Text>

                  <Pressable
                    onPress={handleDeleteAccount}
                    className="flex-row items-center justify-center border border-error/40 bg-error/10 rounded-2xl h-14 active:bg-error/20"
                  >
                    <Text className="text-error font-black text-sm uppercase tracking-0.5">
                      Delete Account
                    </Text>
                  </Pressable>
                </GlassCard>
              </AnimatedSection>

              {/* Sign Out */}
              <AnimatedSection direction="up" delay={600}>
                <Pressable
                  onPress={handleSignOut}
                  className="bg-input border border-border rounded-2xl h-14 items-center justify-center active:bg-card mb-10"
                >
                  <Text className="text-text font-bold text-sm uppercase tracking-widest">
                    Sign Out
                  </Text>
                </Pressable>
              </AnimatedSection>

              {error && <Text className="text-error text-center mb-6 font-bold">{error}</Text>}
            </View>
          </ScrollView>
        </KeyboardAvoidingView>
      </SafeAreaView>
    </PremiumBackground>
  );
}

import { Ionicons } from '@expo/vector-icons';
import React, { useState } from 'react';
import { Modal, View, Text, Pressable, ActivityIndicator, TextInput } from 'react-native';

import { apiService } from '@/services/api.service';
import { THEME } from '@/theme/theme';
import { logger, LogTag } from '@/utils/logger';

interface RatingPromptModalProps {
  visible: boolean;
  booking: {
    id: string;
    booking_id?: string;
    salon_name?: string;
    business_name?: string;
    service_name?: string | string[];
    service_date?: string;
    service_time?: string;
    services?: { id?: string; name?: string; service_name?: string; [key: string]: unknown }[];
    service?: { id?: string; name?: string; service_name?: string; [key: string]: unknown };
    [key: string]: unknown;
  };
  onClose: () => void;
  onSuccess: () => void;
}

export const RatingPromptModal: React.FC<RatingPromptModalProps> = ({
  visible,
  booking,
  onClose,
  onSuccess,
}) => {
  const [rating, setRating] = useState<number | null>(null);

  const [comment, setComment] = useState('');

  const [isLoading, setIsLoading] = useState(false);

  const [actionType, setActionType] = useState<'submit' | 'ignore' | null>(null);

  const [error, setError] = useState<string | null>(null);

  const [fullBooking, setFullBooking] = useState<{
    salon_name?: string;
    business_name?: string;
    business?: { salon_name?: string };
    service_date?: string;
    service_time?: string;
    service_name?: string | string[] | { name?: string; service_name?: string };
    services?: { name?: string; service_name?: string }[];
    service?: { name?: string; service_name?: string };
    [key: string]: unknown;
  }>(booking);

  React.useEffect(() => {
    let isMounted = true;
    if (booking) {
      setFullBooking(booking); // Set immediately

      // If the booking is missing service details, fetch the full booking
      if (!booking.service_name && !booking.services && !booking.service) {
        const fetchId = booking.id; // Use UUID for supabase queries
        if (fetchId) {
          apiService
            .getBookingById(fetchId)
            .then((b) => {
              if (isMounted) {
                setFullBooking({ ...booking, ...b });
              }
            })
            .catch((e) => {
              logger.warn(LogTag.API, 'Failed to fetch full booking for rating', e);
            });
        }
      }
    }
    return () => {
      isMounted = false;
    };
  }, [booking]);

  const salonName =
    fullBooking.salon_name ||
    fullBooking.business_name ||
    fullBooking.business?.salon_name ||
    'Premium Studio';

  const getServiceName = (b: {
    service_date?: string;
    service_time?: string;
    service_name?: string | string[] | { name?: string; service_name?: string };
    services?: { name?: string; service_name?: string }[];
    service?: { name?: string; service_name?: string };
    [key: string]: unknown;
  }): string => {
    const fallback =
      b?.service_date && b?.service_time
        ? `Booking on ${b.service_date} at ${b.service_time.substring(0, 5)}`
        : 'Service Experience';

    if (!b) return fallback;
    if (typeof b.service_name === 'string') return b.service_name;
    if (Array.isArray(b.service_name) && b.service_name.length > 0) {
      if (typeof b.service_name[0] === 'string') return b.service_name.join(', ');
      return (
        (b.service_name as unknown[])
          .map(
            (s: unknown) =>
              (s as { name?: string; service_name?: string })?.name ||
              (s as { name?: string; service_name?: string })?.service_name ||
              '',
          )
          .filter(Boolean)
          .join(', ') || fallback
      );
    }
    if (b.service_name && typeof b.service_name === 'object') {
      return (
        (b.service_name as { name?: string; service_name?: string }).name ||
        (b.service_name as { name?: string; service_name?: string }).service_name ||
        fallback
      );
    }
    if (Array.isArray(b.services) && b.services.length > 0) {
      return (
        (b.services as unknown[])
          .map(
            (s: unknown) =>
              (s as { name?: string; service_name?: string })?.name ||
              (s as { name?: string; service_name?: string })?.service_name ||
              '',
          )
          .filter(Boolean)
          .join(', ') || fallback
      );
    }
    if (b.service && typeof b.service === 'object') {
      return b.service.name || b.service.service_name || fallback;
    }
    return fallback;
  };

  const serviceName = getServiceName(fullBooking);

  const handleSubmit = async () => {
    if (!rating) {
      setError('Please select a rating');
      return;
    }

    setIsLoading(true);
    setActionType('submit');
    setError(null);

    try {
      await apiService.submitRating(booking.id, rating, comment.trim() || undefined);

      logger.info(LogTag.API, `Successfully submitted review for booking: ${booking.id}`);

      onSuccess();
    } catch (err: unknown) {
      setError((err instanceof Error ? err.message : String(err)) || 'Failed to submit review');
    } finally {
      setIsLoading(false);
      setActionType(null);
    }
  };

  const handleIgnore = async () => {
    setIsLoading(true);
    setActionType('ignore');
    setError(null);

    try {
      await apiService.ignoreRating(booking.id);

      logger.info(LogTag.API, `Successfully ignored review for booking: ${booking.id}`);

      onSuccess();
    } catch (err: unknown) {
      setError((err instanceof Error ? err.message : String(err)) || 'Failed to skip review');
    } finally {
      setIsLoading(false);
      setActionType(null);
    }
  };

  return (
    <Modal transparent animationType="fade" visible={visible} onRequestClose={onClose}>
      <View className="flex-1 justify-center items-center bg-black/80 px-6">
        <View
          className="w-full rounded-full bg-gray-500 p-6"
          style={[
            {
              maxWidth: 340,
              overflow: 'hidden',
              borderWidth: 1,
              borderColor: 'rgba(255,255,255,0.05)',
            },
          ]}
        >
          {/* Header */}
          <View className="flex-row justify-between items-start mb-8">
            <View className="flex-1 pr-3">
              <Text className="text-3xl font-black text-primary tracking-tighter mb-1.5">
                Rate Experience
              </Text>

              <Text
                className="text-textSecondary text-sm tracking-wide"
                style={[
                  {
                    textTransform: 'uppercase',
                  },
                ]}
              >
                {salonName}
              </Text>
            </View>

            <Pressable
              className="w-8 h-8 rounded-full justify-center items-center"
              onPress={onClose}
              disabled={isLoading}
              style={[
                {
                  backgroundColor: 'rgba(255,255,255,0.04)',
                },
              ]}
            >
              <Ionicons name="close" size={18} color={THEME.colors.textSecondary} />
            </Pressable>
          </View>

          {/* Service Name */}
          <View className="mb-8">
            <Text className="text-3xl font-black text-text leading-9 tracking-tighter">
              {serviceName}
            </Text>

            {booking.service_date && (
              <View className="flex-row items-center mt-4">
                <Ionicons name="calendar-outline" size={14} color={THEME.colors.primary} />

                <Text className="text-textSecondary ml-2 text-sm font-semibold">
                  {booking.service_date} • {booking.service_time || ''}
                </Text>
              </View>
            )}
          </View>

          {/* Rating */}
          <View className="items-center mb-8">
            <Text className="text-textSecondary text-sm mb-4.5">How was your experience?</Text>

            <View className="flex-row">
              {[1, 2, 3, 4, 5].map((star) => {
                const active = rating !== null && star <= rating;

                return (
                  <Pressable
                    key={star}
                    onPress={() => {
                      setRating(star);
                      setError(null);
                    }}
                    disabled={isLoading}
                    className="mx-1"
                  >
                    <Ionicons
                      name={active ? 'star' : 'star-outline'}
                      size={34}
                      color={active ? THEME.colors.primary : 'rgba(255,255,255,0.18)'}
                    />
                  </Pressable>
                );
              })}
            </View>
          </View>

          {/* Review */}
          <View className="mb-6">
            <TextInput
              className="min-h-28 rounded-3xl px-4.5 py-4 text-text"
              value={comment}
              onChangeText={setComment}
              placeholder="Share your feedback..."
              placeholderTextColor={THEME.colors.textSecondary}
              multiline
              numberOfLines={4}
              textAlignVertical="top"
              editable={!isLoading}
              style={[
                {
                  backgroundColor: 'rgba(255,255,255,0.03)',
                  borderWidth: 1,
                  borderColor: 'rgba(255,255,255,0.05)',
                },
              ]}
            />
          </View>

          {/* Error */}
          {error && (
            <Text
              className="mb-4.5 text-center text-sm"
              style={[
                {
                  color: '#ff6b6b',
                },
              ]}
            >
              {error}
            </Text>
          )}

          {/* Actions */}
          <View>
            <Pressable
              className="h-14 rounded-full justify-center items-center"
              onPress={handleSubmit}
              disabled={isLoading || !rating}
              style={[
                {
                  backgroundColor: rating ? THEME.colors.primary : 'rgba(255,255,255,0.08)',
                },
              ]}
            >
              {isLoading && actionType === 'submit' ? (
                <ActivityIndicator size="small" color="#000" />
              ) : (
                <Text
                  className="font-black tracking-wide text-sm"
                  style={[
                    {
                      color: rating ? '#000' : THEME.colors.textSecondary,
                    },
                  ]}
                >
                  SUBMIT REVIEW
                </Text>
              )}
            </Pressable>

            <Pressable onPress={handleIgnore} disabled={isLoading} className="items-center mt-5">
              {isLoading && actionType === 'ignore' ? (
                <ActivityIndicator size="small" color={THEME.colors.textSecondary} />
              ) : (
                <Text className="text-textSecondary font-bold tracking-wide text-sm">
                  MAYBE LATER
                </Text>
              )}
            </Pressable>
          </View>
        </View>
      </View>
    </Modal>
  );
};

import React, { useState, useEffect, useCallback } from 'react';

import { RatingPromptModal } from './RatingPromptModal';
import { apiService } from '@/services/api.service';
import { useAuthStore } from '@/store/auth.store';
import { logger, LogTag } from '@/utils/logger';

import type { Booking } from '@/types/booking.types';

export const RatingPromptProvider: React.FC = () => {
  const session = useAuthStore((s) => s.session);
  const [pendingBookings, setPendingBookings] = useState<Booking[]>([]);
  const [dismissedBookingIds, setDismissedBookingIds] = useState<string[]>([]);
  const [visible, setVisible] = useState(false);

  const pendingBooking = pendingBookings[0] || null;

  const fetchPendingRatings = useCallback(async () => {
    if (!session?.user?.id) {
      setPendingBookings([]);
      setVisible(false);
      return;
    }

    try {
      const bookings = await apiService.getPendingRatings();
      if (Array.isArray(bookings)) {
        const filtered = bookings.filter(
          (b) =>
            (b as Booking) && (b as Booking).id && !dismissedBookingIds.includes((b as Booking).id),
        );
        setPendingBookings(filtered as Booking[]);
        setVisible(filtered.length > 0);
      }
    } catch (error) {
      logger.error(LogTag.API, 'Failed to fetch pending ratings for customer:', error);
      setPendingBookings([]);
      setVisible(false);
    }
  }, [session?.user?.id, dismissedBookingIds]);

  useEffect(() => {
    fetchPendingRatings();
  }, [fetchPendingRatings]);

  // Poll for new pending ratings every 60 seconds when session is active
  useEffect(() => {
    if (!session?.user?.id) return;

    const interval = setInterval(fetchPendingRatings, 60000);
    return () => clearInterval(interval);
  }, [fetchPendingRatings, session?.user?.id]);

  const handleModalClose = () => {
    if (!pendingBooking) return;
    setDismissedBookingIds((prev) => [...prev, pendingBooking.id]);
    setVisible(false);
    // Remove the current booking from list
    setPendingBookings((prev) => prev.filter((b) => b.id !== pendingBooking.id));
  };

  const handleSuccess = () => {
    if (!pendingBooking) return;
    setVisible(false);
    // Remove the current booking from list
    setPendingBookings((prev) => prev.filter((b) => b.id !== pendingBooking.id));
    // Trigger quick refetch to see if another completed booking needs rating
    setTimeout(fetchPendingRatings, 800);
  };

  if (!session?.user?.id || !pendingBooking) {
    return null;
  }

  return (
    <RatingPromptModal
      visible={visible}
      booking={pendingBooking as unknown as Record<string, unknown>}
      onClose={handleModalClose}
      onSuccess={handleSuccess}
    />
  );
};

