import { router } from 'expo-router';
import React, { useEffect, useState } from 'react';
import { View, Text } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withTiming,
  withDelay,
  Easing,
  runOnJS,
  withSequence,
  withRepeat,
  interpolate,
} from 'react-native-reanimated';

import type { Session } from '@supabase/supabase-js';
import { AnimatedSection } from '@/components/animations/AnimatedSection';
import { PremiumBackground } from '@/components/ui/PremiumBackground';
import { authService } from '@/services/auth.service';
import { useAuthStore } from '@/store/auth.store';
import { useOnboardingStore } from '@/store/onboarding.store';

const PHRASES = [
  'Book Instantly',
  'Manage Effortlessly',
  'Grow Your Business',
  'Luxury Meets Technology',
];

export default function Splash() {
  const setSession = useAuthStore((s) => s.setSession);
  const { selectedRole, setSplashShown } = useOnboardingStore();
  const [currentPhraseIndex, setCurrentPhraseIndex] = useState(0);

  const logoOpacity = useSharedValue(0);
  const logoScale = useSharedValue(0.8);
  const taglineOpacity = useSharedValue(0);
  const phraseOpacity = useSharedValue(0);
  const phraseTranslateY = useSharedValue(10);

  const logoStyle = useAnimatedStyle(() => ({
    opacity: logoOpacity.value,
    transform: [{ scale: logoScale.value }],
  }));

  const taglineStyle = useAnimatedStyle(() => ({
    opacity: taglineOpacity.value,
    transform: [{ translateY: interpolate(taglineOpacity.value, [0, 1], [20, 0]) }],
  }));

  const phraseStyle = useAnimatedStyle(() => ({
    opacity: phraseOpacity.value,
    transform: [{ translateY: phraseTranslateY.value }],
  }));

  useEffect(() => {
    let timeout1: NodeJS.Timeout;
    let timeout2: NodeJS.Timeout;

    const initialize = async () => {
      try {
        const {
          data: { session },
        } = await authService.getSession();
        await setSession(session);

        logoOpacity.value = withTiming(1, { duration: 1200, easing: Easing.out(Easing.quad) });
        logoScale.value = withTiming(1, { duration: 1200, easing: Easing.out(Easing.back(1.5)) });

        taglineOpacity.value = withDelay(800, withTiming(1, { duration: 1000 }));

        timeout1 = setTimeout(() => {
          startPhraseRotation();
        }, 1500);

        timeout2 = setTimeout(() => {
          setSplashShown(true);
          handleNavigation(session);
        }, 4500);
      } catch (error) {
        console.error('Initialization error:', error);
        router.replace('/(public)/welcome');
      }
    };

    initialize();

    return () => {
      clearTimeout(timeout1);
      clearTimeout(timeout2);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const startPhraseRotation = () => {
    phraseOpacity.value = withRepeat(
      withSequence(
        withTiming(1, { duration: 600 }),
        withDelay(800, withTiming(0, { duration: 600 })),
      ),
      -1,
      false,
      () => {
        runOnJS(nextPhrase)();
      },
    );
    phraseTranslateY.value = withRepeat(
      withSequence(
        withTiming(0, { duration: 600 }),
        withDelay(800, withTiming(-10, { duration: 600 })),
      ),
      -1,
    );
  };

  const nextPhrase = () => {
    setCurrentPhraseIndex((prev) => (prev + 1) % PHRASES.length);
    phraseTranslateY.value = 10;
  };

  const handleNavigation = (session: Session | null) => {
    if (session) {
      const role = session.user.user_metadata?.role || selectedRole;
      router.replace(role === 'Owner' ? '/(owner)' : '/(customer)');
    } else {
      router.replace('/(public)/welcome');
    }
  };

  return (
    <PremiumBackground>
      <View className="flex-1 items-center justify-center px-luxury">
        <Animated.View style={logoStyle} className="shadow-lg shadow-secondary/50">
          <View className="w-28 h-28 bg-accent-premium rounded-3xl items-center justify-center rotate-12">
            <Text className="text-black text-5xl font-bold italic -rotate-12">C</Text>
          </View>
        </Animated.View>

        <Animated.View style={logoStyle} className="mt-8">
          <Text className="text-text text-5xl font-bold tracking-tighter">
            Cus<Text className="text-accent-premium">Own</Text>
          </Text>
        </Animated.View>

        <Animated.View style={taglineStyle} className="mt-4">
          <Text className="text-textLight text-lg font-medium tracking-1 uppercase text-center">
            Elevated Experiences
          </Text>
        </Animated.View>

        <View className="h-16 mt-12 items-center justify-center">
          <Animated.Text
            style={phraseStyle}
            className="text-accent-premium text-xl font-semibold italic text-center"
          >
            {PHRASES[currentPhraseIndex]}
          </Animated.Text>
        </View>
      </View>

      <AnimatedSection
        direction="up"
        delay={2000}
        className="absolute bottom-16 w-full items-center"
      >
        <Text className="text-textSecondary/50 text-xs tracking-2 uppercase">
          Powered by Gold Protocol
        </Text>
      </AnimatedSection>
    </PremiumBackground>
  );
}

import 'react-native-get-random-values';
import 'react-native-url-polyfill/auto';

import { createClient } from '@supabase/supabase-js';
import * as SecureStore from 'expo-secure-store';
import * as WebBrowser from 'expo-web-browser';

import { ensureWebCryptoForSupabasePkce } from '@/lib/webCryptoPolyfill';

ensureWebCryptoForSupabasePkce();

const ExpoSecureStoreAdapter = {
  getItem: (key: string) => {
    return SecureStore.getItemAsync(key);
  },
  setItem: (key: string, value: string) => {
    return SecureStore.setItemAsync(key, value);
  },
  removeItem: (key: string) => {
    return SecureStore.deleteItemAsync(key);
  },
};

const supabaseUrl = process.env.EXPO_PUBLIC_SUPABASE_URL || '';
const supabaseAnonKey = process.env.EXPO_PUBLIC_SUPABASE_ANON_KEY || '';

if (__DEV__) {
  if (!supabaseUrl || !supabaseAnonKey) {
    console.error(
      '[Supabase] Missing EXPO_PUBLIC_SUPABASE_URL or EXPO_PUBLIC_SUPABASE_ANON_KEY. All data queries will fail. Restart with: npx expo start -c',
    );
  } else if (!supabaseUrl.includes('.supabase.co')) {
    console.warn(
      '[Supabase] EXPO_PUBLIC_SUPABASE_URL does not look like a Supabase project URL:',
      supabaseUrl,
    );
  }
}

export const supabase = createClient(supabaseUrl, supabaseAnonKey, {
  auth: {
    storage: ExpoSecureStoreAdapter,
    autoRefreshToken: true,
    persistSession: true,
    detectSessionInUrl: false,
    flowType: 'pkce',
  },
});

// Set a custom URL opener for OAuth flows
// This allows Supabase to handle the "redirectTo" logic internally
// while using Expo's WebBrowser for the actual window.

supabase.auth.onAuthStateChange((event, session) => {
  // Just to ensure connectivity
});

// We wrap the OAuth opener in a helper
export const openAuthSession = async (url: string, returnUrl: string) => {
  return await WebBrowser.openAuthSessionAsync(url, returnUrl);
};

import { supabase } from '@/lib/supabase';
import { apiService } from '@/services/api.service';
import { useAuthStore } from '@/store/auth.store';

export interface HealthCheckResult {
  id: string;
  name: string;
  status: 'pending' | 'success' | 'error' | 'warning';
  message: string;
  details?: unknown;
}

export const apiChecker = {
  /**
   * Check if the backend API is reachable and healthy.
   */
  async checkBackendHealth(): Promise<HealthCheckResult> {
    try {
      const startTime = Date.now();
      const result = await apiService.checkHealth();
      const duration = Date.now() - startTime;

      return {
        id: 'supabase-health',
        name: 'Supabase connectivity',
        status: result.status as HealthCheckResult['status'],
        message: `${result.message} (${duration}ms)`,
        details: result.details,
      };
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Connection failed';
      return {
        id: 'supabase-health',
        name: 'Supabase connectivity',
        status: 'error',
        message,
        details: err,
      };
    }
  },

  /**
   * Check if the Supabase Auth session is active and valid.
   */
  async checkAuthSession(): Promise<HealthCheckResult> {
    try {
      const {
        data: { session },
        error,
      } = await supabase.auth.getSession();

      if (error) throw error;

      if (!session) {
        return {
          id: 'auth-session',
          name: 'Supabase Auth Session',
          status: 'warning',
          message: 'No active session found. User might be logged out.',
        };
      }

      const expiresAt = new Date(session.expires_at! * 1000);
      const isExpired = expiresAt < new Date();

      return {
        id: 'auth-session',
        name: 'Supabase Auth Session',
        status: isExpired ? 'error' : 'success',
        message: isExpired
          ? 'Session active'
          : `Session active (Expires: ${expiresAt.toLocaleString()})`,
        details: { user: session.user.email, id: session.user.id },
      };
    } catch (err: unknown) {
      return {
        id: 'auth-session',
        name: 'Supabase Auth Session',
        status: 'error',
        message: err instanceof Error ? err.message : 'Failed to retrieve session',
      };
    }
  },

  /**
   * Verify Zustand auth state is in sync with Supabase.
   */
  async verifyZustandSync(): Promise<HealthCheckResult> {
    try {
      const {
        data: { session: supabaseSession },
      } = await supabase.auth.getSession();
      const { session: zustandSession, user: zustandUser } = useAuthStore.getState();

      const inSync =
        !!supabaseSession === !!zustandSession && supabaseSession?.user.id === zustandUser?.id;

      return {
        id: 'zustand-sync',
        name: 'Zustand Store Sync',
        status: inSync ? 'success' : 'error',
        message: inSync ? 'Zustand is synced with Supabase' : 'Zustand store out of sync!',
        details: {
          supabaseUser: supabaseSession?.user.email,
          zustandUser: zustandUser?.email,
        },
      };
    } catch (err) {
      return {
        id: 'zustand-sync',
        name: 'Zustand Store Sync',
        status: 'error',
        message: 'Failed to verify sync',
      };
    }
  },

  /**
   * Test direct database read (if RLS allows it).
   */
  async testDatabaseRead(): Promise<HealthCheckResult> {
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (!user) throw new Error('Auth required for DB read test');

      const { data, error, status } = await supabase.from('user_profiles').select('*').limit(1);

      if (error) {
        if (status === 406 || error.code === '42501') {
          return {
            id: 'db-read',
            name: 'DB Read (RLS Check)',
            status: 'error',
            message: 'RLS Policy Violation: Permission denied.',
            details: error,
          };
        }
        throw error;
      }

      return {
        id: 'db-read',
        name: 'DB Read (User Profiles)',
        status: data && data.length > 0 ? 'success' : 'warning',
        message:
          data && data.length > 0
            ? 'Successfully read from DB'
            : 'Read successful but returned 0 rows (Check RLS)',
        details: data,
      };
    } catch (err: unknown) {
      return {
        id: 'db-read',
        name: 'DB Read Test',
        status: 'error',
        message: err instanceof Error ? err.message : 'Failed to read from database',
      };
    }
  },

  /**
   * Test Supabase database connection (Businesses fetching).
   */
  async testBusinessesSupabase(): Promise<HealthCheckResult> {
    try {
      const startTime = Date.now();
      const { data, error } = await supabase.from('businesses').select('id').limit(1);
      const duration = Date.now() - startTime;

      if (error) throw error;

      return {
        id: 'supabase-businesses',
        name: 'Businesses Supabase Fetch',
        status: 'success',
        message: `Direct Supabase fetch successful in ${duration}ms`,
        details: data,
      };
    } catch (err: unknown) {
      return {
        id: 'supabase-businesses',
        name: 'Businesses Supabase Fetch',
        status: 'error',
        message: err instanceof Error ? err.message : 'Supabase request failed',
      };
    }
  },

  /**
   * Verify persistence after app restart (simulated).
   */
  async verifyPersistence(): Promise<HealthCheckResult> {
    const {
      data: { session },
    } = await supabase.auth.getSession();

    return {
      id: 'persistence',
      name: 'Session Persistence',
      status: session ? 'success' : 'warning',
      message: session ? 'Session persisted in SecureStore' : 'No persisted session found',
    };
  },

  /**
   * Test database write operation (Update own profile).
   */
  async testDatabaseWrite(): Promise<HealthCheckResult> {
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (!user) throw new Error('Auth required for DB write test');

      const { data: profile } = await supabase
        .from('user_profiles')
        .select('full_name')
        .eq('id', user.id)
        .single();

      const originalName = profile?.full_name || 'User';
      const testName = `${originalName} (Verified)`;

      const { error: updateError, status } = await supabase
        .from('user_profiles')
        .update({ full_name: testName })
        .eq('id', user.id);

      if (updateError) {
        if (status === 403 || updateError.code === '42501') {
          return {
            id: 'db-write',
            name: 'DB Write (Update Profile)',
            status: 'error',
            message: 'RLS Policy Violation: Cannot update profile.',
            details: updateError,
          };
        }
        throw updateError;
      }

      await supabase.from('user_profiles').update({ full_name: originalName }).eq('id', user.id);

      return {
        id: 'db-write',
        name: 'DB Write (Update Profile)',
        status: 'success',
        message: 'Database write (update) verified successfully.',
      };
    } catch (err: unknown) {
      return {
        id: 'db-write',
        name: 'DB Write Test',
        status: 'error',
        message: err instanceof Error ? err.message : 'Failed to write to database',
      };
    }
  },
};

import { getActorUserId } from './booking-rpc';
import { listOwnerBookings } from './bookings';
import { listOwnerBusinesses } from './businesses';
import { logger, LogTag } from '@/utils/logger';

import type { Booking } from '@/types/booking.types';
import type { Business, BusinessStats } from '@/types/business.types';

const OWNER_ANALYTICS_RPC = 'get_owner_analytics_advanced';

function bookingDateKey(b: Booking): string {
  return b.date || (b.slot as { date?: string } | undefined)?.date || '';
}

function filterBookingsByRange(bookings: Booking[], fromDate?: string, toDate?: string): Booking[] {
  if (!fromDate && !toDate) return bookings;
  return bookings.filter((b) => {
    const d = bookingDateKey(b);
    if (!d) return true;
    if (fromDate && d < fromDate) return false;
    if (toDate && d > toDate) return false;
    return true;
  });
}

function computeStats(
  bookings: Booking[],
  businessCount: number,
): BusinessStats & {
  rejected_bookings: number;
  no_show_count: number;
} {
  const pending = bookings.filter((b) => b.status === 'pending').length;
  const confirmed = bookings.filter((b) => b.status === 'confirmed').length;
  const rejected = bookings.filter((b) => b.status === 'rejected').length;
  const cancelled = bookings.filter((b) => b.status === 'cancelled').length;
  const noShow = bookings.filter((b) => b.status === 'no_show' || b.no_show).length;
  const revenue = bookings
    .filter((b) => b.status === 'completed' || b.status === 'confirmed')
    .reduce((sum, b) => sum + (Number(b.price) || 0), 0);

  return {
    total_bookings: bookings.length,
    pending_bookings: pending,
    confirmed_bookings: confirmed,
    cancelled_bookings: cancelled,
    total_businesses: businessCount,
    revenue,
    rejected_bookings: rejected,
    no_show_count: noShow,
  };
}

export type OwnerDashboardPayload = {
  stats: ReturnType<typeof computeStats>;
  recentBookings: Booking[];
  todaysBookings: Booking[];
  pendingBookingsList: Booking[];
  bookingsByBusiness: Record<string, Booking[]>;
  businesses?: Business[];
};

export async function getOwnerDashboard(params?: {
  businessId?: string;
  fromDate?: string;
  toDate?: string;
}): Promise<OwnerDashboardPayload> {
  const ownerId = await getActorUserId();
  const businessId =
    params?.businessId && params.businessId !== 'all' ? params.businessId : undefined;

  const [businesses, allBookings] = await Promise.all([
    listOwnerBusinesses(ownerId),
    listOwnerBookings(ownerId, businessId),
  ]);

  const bookings = filterBookingsByRange(allBookings, params?.fromDate, params?.toDate);
  const today = new Date().toISOString().slice(0, 10);

  const pendingBookingsList = bookings.filter((b) => b.status === 'pending');
  const todaysBookings = bookings.filter((b) => bookingDateKey(b) === today);
  const recentBookings = [...bookings]
    .sort((a, b) => String(b.created_at).localeCompare(String(a.created_at)))
    .slice(0, 50);

  const bookingsByBusiness: Record<string, Booking[]> = {};
  for (const b of bookings) {
    const bizId = b.business_id || b.business?.id;
    if (!bizId) continue;
    if (!bookingsByBusiness[bizId]) bookingsByBusiness[bizId] = [];
    bookingsByBusiness[bizId].push(b);
  }

  const stats = computeStats(bookings, businesses.length);

  return {
    stats,
    recentBookings,
    todaysBookings,
    pendingBookingsList,
    bookingsByBusiness,
    businesses,
  };
}

export async function getOwnerStats(businessId?: string): Promise<BusinessStats> {
  const dashboard = await getOwnerDashboard({
    businessId: businessId && businessId !== 'all' ? businessId : 'all',
  });
  return dashboard.stats;
}

export type OwnerAnalyticsOverview = {
  confirmedBookings?: number;
  rejectedBookings?: number;
  cancelledBookings?: number;
  totalRevenue?: number;
  totalRevenueCents?: number;
  totalBookings?: number;
  pendingBookings?: number;
  conversionRate?: number;
  noShowRate?: number;
  services?: { name?: string; serviceName?: string; bookingCount?: number; count?: number }[];
  [key: string]: unknown;
};

export type OwnerAnalyticsPayload = {
  overview?: OwnerAnalyticsOverview;
  daily?: { date: string; totalBookings?: number; revenue?: number }[];
  peakHours?: { hour: number; bookingCount?: number }[];
  advanced?: {
    peakHoursHeatmap?: { hour: number; bookingCount?: number }[];
    servicePopularityRanking?: {
      serviceName?: string;
      name?: string;
      bookingCount?: number;
      count?: number;
    }[];
    [key: string]: unknown;
  };
  [key: string]: unknown;
};

export async function getOwnerAnalytics(params: {
  businessId: string;
  type?: string;
  startDate?: string;
  endDate?: string;
  aggregated?: boolean;
}): Promise<OwnerAnalyticsPayload | null> {
  try {
    const ownerId = await getActorUserId();
    const targetBusinessId =
      params.businessId && params.businessId !== 'all' ? params.businessId : undefined;

    const [businesses, allBookings] = await Promise.all([
      listOwnerBusinesses(ownerId),
      listOwnerBookings(ownerId, targetBusinessId),
    ]);

    // Filter bookings by date range if provided
    const bookings = filterBookingsByRange(allBookings, params.startDate, params.endDate);

    // 1. Overview metrics
    const confirmed = bookings.filter(
      (b) => b.status === 'confirmed' || b.status === 'completed',
    ).length;
    const rejected = bookings.filter((b) => b.status === 'rejected').length;
    const cancelled = bookings.filter((b) => b.status === 'cancelled').length;
    const total = bookings.length;
    const pending = bookings.filter((b) => b.status === 'pending').length;
    const noShow = bookings.filter((b) => b.status === 'no_show' || b.no_show).length;

    const totalRevenueCents = bookings
      .filter((b) => b.status === 'confirmed' || b.status === 'completed')
      .reduce((sum, b) => sum + (Number(b.total_price_cents) || Number(b.price) * 100 || 0), 0);

    const conversionRate = total > 0 ? (confirmed / total) * 100 : 0;
    const noShowRate = total > 0 ? (noShow / total) * 100 : 0;

    // 2. Services popularity
    const serviceCounts: Record<string, { name: string; count: number }> = {};
    for (const b of bookings) {
      const services = b.services || (b.service ? [b.service] : []);
      for (const s of services) {
        if (!s || !s.name) continue;
        if (!serviceCounts[s.name]) {
          serviceCounts[s.name] = { name: s.name, count: 0 };
        }
        serviceCounts[s.name].count++;
      }
    }
    const sortedServices = Object.values(serviceCounts)
      .sort((a, b) => b.count - a.count)
      .map((s) => ({
        serviceName: s.name,
        bookingCount: s.count,
      }));

    // 3. Peak traffic hours (initialize standard hours: 9 AM to 9 PM)
    const hourCounts: Record<number, number> = {};
    for (let h = 9; h <= 21; h++) {
      hourCounts[h] = 0;
    }
    for (const b of bookings) {
      const slotStart = b.time || b.slot?.start_time;
      if (slotStart) {
        const hour = parseInt(String(slotStart).split(':')[0], 10);
        if (!isNaN(hour)) {
          hourCounts[hour] = (hourCounts[hour] || 0) + 1;
        }
      }
    }
    const peakHours = Object.entries(hourCounts)
      .map(([h, count]) => ({
        hour: parseInt(h, 10),
        bookingCount: count,
      }))
      .sort((a, b) => a.hour - b.hour);

    // 4. Daily Trend
    const dailyGroups: Record<
      string,
      { date: string; totalBookings: number; revenueCents: number }
    > = {};

    const datesToFill: string[] = [];
    if (params.startDate && params.endDate) {
      const curr = new Date(params.startDate);
      const end = new Date(params.endDate);
      let limit = 0;
      while (curr <= end && limit < 40) {
        const dateStr = curr.toISOString().slice(0, 10);
        datesToFill.push(dateStr);
        curr.setDate(curr.getDate() + 1);
        limit++;
      }
    } else {
      for (let i = 6; i >= 0; i--) {
        const d = new Date();
        d.setDate(d.getDate() - i);
        datesToFill.push(d.toISOString().slice(0, 10));
      }
    }

    datesToFill.forEach((d) => {
      dailyGroups[d] = { date: d, totalBookings: 0, revenueCents: 0 };
    });

    for (const b of bookings) {
      const dateStr = bookingDateKey(b);
      if (!dateStr) continue;
      if (!dailyGroups[dateStr]) {
        dailyGroups[dateStr] = { date: dateStr, totalBookings: 0, revenueCents: 0 };
      }
      dailyGroups[dateStr].totalBookings++;
      if (b.status === 'confirmed' || b.status === 'completed') {
        dailyGroups[dateStr].revenueCents +=
          Number(b.total_price_cents) || Number(b.price) * 100 || 0;
      }
    }

    const dailyTrend = Object.values(dailyGroups)
      .sort((a, b) => a.date.localeCompare(b.date))
      .map((dg) => ({
        date: dg.date,
        totalBookings: dg.totalBookings,
        revenue: dg.revenueCents,
      }));

    return {
      overview: {
        confirmedBookings: confirmed,
        rejectedBookings: rejected,
        cancelledBookings: cancelled,
        totalRevenueCents: totalRevenueCents,
        totalRevenue: totalRevenueCents / 100,
        totalBookings: total,
        pendingBookings: pending,
        conversionRate,
        noShowRate,
        services: sortedServices.map((s) => ({ name: s.serviceName, count: s.bookingCount })),
      },
      daily: dailyTrend,
      peakHours: peakHours,
      advanced: {
        peakHoursHeatmap: peakHours,
        servicePopularityRanking: sortedServices,
      },
    };
  } catch (err) {
    logger.error(LogTag.API, 'getOwnerAnalytics client computation failed', err);
    throw err;
  }
}

import Constants from 'expo-constants';
import * as Device from 'expo-device';
import * as Notifications from 'expo-notifications';
import { Platform } from 'react-native';

import { THEME } from '@/theme/theme';

Notifications.setNotificationHandler({
  handleNotification: async () => ({
    shouldShowAlert: true,
    shouldPlaySound: true,
    shouldSetBadge: true,
    shouldShowBanner: true,
    shouldShowList: true,
  }),
});

export async function registerForPushNotificationsAsync() {
  let token;

  if (Platform.OS === 'android') {
    await Notifications.setNotificationChannelAsync('default', {
      name: 'default',
      importance: Notifications.AndroidImportance.MAX,
      vibrationPattern: [0, 250, 250, 250],
      lightColor: THEME.colors.background,
    });
  }

  if (Device.isDevice) {
    const { status: existingStatus } = await Notifications.getPermissionsAsync();
    let finalStatus = existingStatus;
    if (existingStatus !== 'granted') {
      const { status } = await Notifications.requestPermissionsAsync();
      finalStatus = status;
    }
    if (finalStatus !== 'granted') {
      console.log('Permission rejected: Disabling remote token registration arrays.');
      return null;
    }
    try {
      token = await Notifications.getExpoPushTokenAsync({
        projectId: Constants.expoConfig?.extra?.eas?.projectId || 'cusown-mobile-parity',
      });
    } catch (e) {
      console.log('Token capture fallback executed locally.');
    }
  } else {
    console.log(
      'Simulated device hardware detected: Falling back to mocked local push dispatcher channel.',
    );
  }

  return token?.data || `ExponentPushToken[mock_${Date.now()}]`;
}

/**
 * Register background and foreground lifecycle observers for live socket triggers
 */
export function setupNotificationListeners(
  onNotification: (notification: Notifications.Notification) => void,
  onResponse: (response: Notifications.NotificationResponse) => void,
) {
  const notificationListener = Notifications.addNotificationReceivedListener(onNotification);
  const responseListener = Notifications.addNotificationResponseReceivedListener(onResponse);

  return () => {
    notificationListener.remove();
    responseListener.remove();
  };
}

/**
 * Proactively dispatch instant native system scheduled push events for testing feature parity loops
 */
export async function scheduleLocalNotification(title: string, body: string, seconds = 2) {
  await Notifications.scheduleNotificationAsync({
    content: {
      title,
      body,
      sound: true,
      data: { route: 'BookingDetails' },
    },
    trigger: {
      type: Notifications.SchedulableTriggerInputTypes.TIME_INTERVAL,
      seconds,
    },
  });
}

import { Dimensions } from 'react-native';

import { getColumns } from './grid';

const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');

// Global spacing token scale to be used in calculation
const SPACING = {
  xs: 4,
  sm: 8,
  md: 16,
  lg: 24,
  xl: 32,
  '2xl': 40,
  '3xl': 48,
};

export const getCardWidth = (
  containerWidth: number = SCREEN_WIDTH,
  gap: number = SPACING.md,
  padding: number = SPACING.md * 2, // Left + Right screen padding
  isLandscape: boolean = false,
) => {
  const columns = getColumns(containerWidth, isLandscape);

  // Total available width minus screen padding and gaps between columns
  const availableWidth = containerWidth - padding;
  const totalGapSpace = gap * (columns - 1);

  return (availableWidth - totalGapSpace) / columns;
};

// Returns a proportional height for horizontal scrolling cards
export const getHorizontalCardSize = (
  type: 'small' | 'medium' | 'large' = 'medium',
  screenWidth: number = SCREEN_WIDTH,
) => {
  const isTablet = screenWidth >= 768;

  switch (type) {
    case 'small':
      return {
        width: isTablet ? 180 : 140,
        height: isTablet ? 200 : 160,
      };
    case 'large':
      return {
        width: isTablet ? 320 : 280,
        height: isTablet ? 360 : 320,
      };
    case 'medium':
    default:
      return {
        width: isTablet ? 240 : 200,
        height: isTablet ? 280 : 240,
      };
  }
};

/**
 * Time utility functions for salon hours and open/closed calculations.
 */

export const parseTimeToMinutes = (t: string | null | undefined): number | null => {
  if (!t || typeof t !== 'string') return null;
  const cleaned = t.trim().toUpperCase();

  // 1. Check if format is HH:MM:SS or HH:MM (24-hour style, e.g., "14:30:00" or "14:30")
  const match24 = cleaned.match(/^([0-9]{1,2}):([0-9]{2})(?::([0-9]{2}))?$/);
  if (match24) {
    const hours = Number(match24[1]);
    const minutes = Number(match24[2]);
    if (hours >= 0 && hours < 24 && minutes >= 0 && minutes < 60) {
      return hours * 60 + minutes;
    }
  }

  // 2. Check if format is HH:MM:SS AM/PM or HH:MM AM/PM (12-hour style, e.g., "02:30 PM" or "2:30:00 PM")
  const match12 = cleaned.match(/^([0-9]{1,2}):([0-9]{2})(?::([0-9]{2}))?\s*(AM|PM)$/);
  if (match12) {
    let hours = Number(match12[1]);
    const minutes = Number(match12[2]);
    const ampm = match12[4];
    if (ampm === 'PM' && hours !== 12) hours += 12;
    if (ampm === 'AM' && hours === 12) hours = 0;
    if (hours >= 0 && hours < 24 && minutes >= 0 && minutes < 60) {
      return hours * 60 + minutes;
    }
  }

  return null;
};

export const formatMinutesTo12Hour = (totalMinutes: number): string => {
  let hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  const ampm = hours >= 12 ? 'PM' : 'AM';
  hours = hours % 12;
  if (hours === 0) hours = 12;
  const minutesStr = minutes < 10 ? `0${minutes}` : `${minutes}`;
  return `${hours}:${minutesStr} ${ampm}`;
};

export interface ShopStatus {
  isOpen: boolean;
  statusText: string;
  opensInText?: string;
  reopeningTime?: string;
}

export const getShopStatus = (
  openingTime: string | null | undefined,
  closingTime: string | null | undefined,
): ShopStatus => {
  const start = parseTimeToMinutes(openingTime);
  const end = parseTimeToMinutes(closingTime);

  if (start === null || end === null) {
    return { isOpen: true, statusText: 'Open Now' };
  }

  const now = new Date();
  const current = now.getHours() * 60 + now.getMinutes();

  let isOpen = false;
  if (end < start) {
    // Overnight shift, e.g., 22:00 to 04:00
    isOpen = current >= start || current < end;
  } else {
    isOpen = current >= start && current < end;
  }

  if (isOpen) {
    return { isOpen: true, statusText: 'Open Now' };
  }

  // It is closed. Let's calculate when it opens!
  let diffMinutes = 0;
  if (current < start) {
    // Opens later today
    diffMinutes = start - current;
  } else {
    // Opens tomorrow
    diffMinutes = 1440 - current + start;
  }

  const hoursLeft = Math.floor(diffMinutes / 60);
  const minutesLeft = diffMinutes % 60;

  let opensInText = '';
  if (hoursLeft === 0) {
    opensInText = `Opens in ${minutesLeft} mins`;
  } else if (hoursLeft < 12) {
    opensInText = `Opens in ${hoursLeft} ${hoursLeft === 1 ? 'hour' : 'hours'}`;
  } else {
    const openingFormatted = formatMinutesTo12Hour(start);
    opensInText = `Opens tomorrow at ${openingFormatted}`;
  }

  return {
    isOpen: false,
    statusText: 'Closed',
    opensInText,
    reopeningTime: formatMinutesTo12Hour(start),
  };
};

/**
 * Format a YYYY-MM-DD date string into a readable format (e.g., "Tue, May 19, 2026")
 */
export function formatBookingDate(dateStr: string | null | undefined): string {
  if (
    !dateStr ||
    dateStr === 'undefined' ||
    dateStr === 'null' ||
    dateStr === 'NaN' ||
    dateStr === '—' ||
    dateStr.trim() === ''
  ) {
    return 'N/A';
  }
  try {
    const trimmed = dateStr.trim().split(/[T ]/)[0];
    const parts = trimmed.split('-');
    if (parts.length === 3) {
      const year = parseInt(parts[0], 10);
      const month = parseInt(parts[1], 10) - 1;
      const day = parseInt(parts[2], 10);
      const date = new Date(year, month, day);
      if (!isNaN(date.getTime())) {
        return date.toLocaleDateString('en-US', {
          weekday: 'short',
          month: 'short',
          day: 'numeric',
          year: 'numeric',
        });
      }
    }
    const date = new Date(trimmed);
    if (!isNaN(date.getTime())) {
      return date.toLocaleDateString('en-US', {
        weekday: 'short',
        month: 'short',
        day: 'numeric',
        year: 'numeric',
      });
    }
  } catch (e) {
    // Ignore error
  }
  return dateStr;
}

/**
 * Format a HH:MM:SS or HH:MM time string into a 12-hour AM/PM format (e.g., "9:00 AM" or "2:30 PM")
 */
export function formatBookingTime(timeStr: string | null | undefined): string {
  if (
    !timeStr ||
    timeStr === 'undefined' ||
    timeStr === 'null' ||
    timeStr === 'NaN' ||
    timeStr === '—' ||
    timeStr.trim() === ''
  ) {
    return 'N/A';
  }
  const minutes = parseTimeToMinutes(timeStr);
  if (minutes !== null) {
    return formatMinutesTo12Hour(minutes);
  }
  return timeStr;
}
